// itch.h — Japannext ITCH v2.02 message codec (decode + encode).
//
// Layouts transcribed from JNX_PLAN.md §3.1/§3.2 (the frozen cheat sheet,
// byte-verified against the official samples). All integers big-endian on
// the wire; all byte access goes through cpp/common/endian.h (no struct
// casts). Alpha fields are stripped of trailing spaces on decode and
// space-padded on encode.
//
// Representation: ONE flat "wide" struct with a type char and the union of
// all per-type fields (only the fields for `type` are meaningful). This is
// the simplest C++11-safe tagged representation — no variant, no unions
// with non-trivial members.
//
// NOTE: decode does not strip meaning — a reference-price `A`
// (order_number == 0) decodes as a normal `A`; that policy lives upstream
// in the market core.
#ifndef JNX_ITCH_H
#define JNX_ITCH_H

#include <cstddef>
#include <cstdint>

namespace jnx {

// Price sentinel: "no reference price" (only in reference-price A msgs).
const uint32_t NO_PRICE = 0x7FFFFFFFu;

struct ItchMsg {
    char type; // 'T','S','L','R','H','Y','A','F','E','D','U','G'

    // T
    uint32_t seconds;
    // Every non-T message: nanoseconds since the last T.
    uint32_t ns;
    // S / R / H / Y / A / F
    char group[5]; // 4-byte Alpha + NUL ("" = blank/system-wide in S)
    // S
    char event; // O/S/Q/M/E/C
    // L
    uint32_t tick_table_id; // also in R
    uint32_t tick_size;
    uint32_t price_start;
    // R / H / Y / A / F
    char orderbook_id[5]; // 4-byte Alpha (SICC code — a string, NOT a number)
    // R
    char isin[13];
    uint32_t round_lot;
    uint32_t price_decimals;
    uint32_t upper_limit;
    uint32_t lower_limit;
    // H / Y
    char state; // H: T/V; Y: 0/1
    // A / F / E / D
    uint64_t order_number;
    // A / F
    char side; // B/S
    uint32_t qty; // also U
    uint32_t price; // also U
    // F
    char attribution[5];
    char order_type; // 'Q' = DLP
    // E
    uint32_t executed_qty;
    uint64_t match_number;
    // U
    uint64_t orig_order_number;
    uint64_t new_order_number;
    // G (GLIMPSE end-of-snapshot)
    uint64_t sequence_number;

    ItchMsg();
};

// Total wire length (including the leading type byte) for a message type;
// -1 for unknown types.
int expected_len(char type);

// Strict decode: len must equal expected_len(type); unknown type fails.
// On failure returns false and, if err != NULL, points *err at a static
// reason string.
bool decode(const unsigned char* buf, size_t len, ItchMsg& out,
            const char** err);

// Encodes msg into buf (caller provides >= expected_len(msg.type) bytes).
// Returns bytes written, or 0 if msg.type is unknown.
size_t encode(const ItchMsg& msg, unsigned char* buf);

} // namespace jnx

#endif // JNX_ITCH_H

// itch.cpp — see itch.h. All field offsets from JNX_PLAN.md §3.2.
#include "itch/itch.h"

#include <cstring>

#include "common/endian.h"

namespace jnx {

namespace {

// Decode a fixed-width Alpha field: copy, strip trailing spaces, NUL-term.
// `out` must have room for width+1 chars.
void get_alpha(const unsigned char* p, size_t width, char* out) {
    size_t n = width;
    while (n > 0 && p[n - 1] == ' ') {
        --n;
    }
    std::memcpy(out, p, n);
    out[n] = '\0';
}

// Encode a fixed-width Alpha field: left-justified, right-padded w/ spaces.
void put_alpha(unsigned char* p, size_t width, const char* s) {
    size_t n = std::strlen(s);
    if (n > width) {
        n = width;
    }
    std::memcpy(p, s, n);
    std::memset(p + n, ' ', width - n);
}

} // namespace

ItchMsg::ItchMsg()
    : type('\0'),
      seconds(0),
      ns(0),
      event('\0'),
      tick_table_id(0),
      tick_size(0),
      price_start(0),
      round_lot(0),
      price_decimals(0),
      upper_limit(0),
      lower_limit(0),
      state('\0'),
      order_number(0),
      side('\0'),
      qty(0),
      price(0),
      order_type('\0'),
      executed_qty(0),
      match_number(0),
      orig_order_number(0),
      new_order_number(0),
      sequence_number(0) {
    group[0] = '\0';
    orderbook_id[0] = '\0';
    isin[0] = '\0';
    attribution[0] = '\0';
}

int expected_len(char type) {
    switch (type) {
        case 'T': return 5;
        case 'S': return 10;
        case 'L': return 17;
        case 'R': return 45;
        case 'H': return 14;
        case 'Y': return 14;
        case 'A': return 30;
        case 'F': return 35;
        case 'E': return 25;
        case 'D': return 13;
        case 'U': return 29;
        case 'G': return 9;
        default: return -1;
    }
}

bool decode(const unsigned char* buf, size_t len, ItchMsg& out,
            const char** err) {
    if (len == 0) {
        if (err != NULL) *err = "empty buffer";
        return false;
    }
    char type = static_cast<char>(buf[0]);
    int want = expected_len(type);
    if (want < 0) {
        if (err != NULL) *err = "unknown message type";
        return false;
    }
    if (len != static_cast<size_t>(want)) {
        if (err != NULL) *err = "length mismatch for message type";
        return false;
    }
    out = ItchMsg();
    out.type = type;
    switch (type) {
        case 'T':
            out.seconds = be_get_u32(buf + 1);
            break;
        case 'S':
            out.ns = be_get_u32(buf + 1);
            get_alpha(buf + 5, 4, out.group);
            out.event = static_cast<char>(buf[9]);
            break;
        case 'L':
            out.ns = be_get_u32(buf + 1);
            out.tick_table_id = be_get_u32(buf + 5);
            out.tick_size = be_get_u32(buf + 9);
            out.price_start = be_get_u32(buf + 13);
            break;
        case 'R':
            out.ns = be_get_u32(buf + 1);
            get_alpha(buf + 5, 4, out.orderbook_id);
            get_alpha(buf + 9, 12, out.isin);
            get_alpha(buf + 21, 4, out.group);
            out.round_lot = be_get_u32(buf + 25);
            out.tick_table_id = be_get_u32(buf + 29);
            out.price_decimals = be_get_u32(buf + 33);
            out.upper_limit = be_get_u32(buf + 37);
            out.lower_limit = be_get_u32(buf + 41);
            break;
        case 'H':
        case 'Y':
            out.ns = be_get_u32(buf + 1);
            get_alpha(buf + 5, 4, out.orderbook_id);
            get_alpha(buf + 9, 4, out.group);
            out.state = static_cast<char>(buf[13]);
            break;
        case 'A':
        case 'F':
            out.ns = be_get_u32(buf + 1);
            out.order_number = be_get_u64(buf + 5);
            out.side = static_cast<char>(buf[13]);
            out.qty = be_get_u32(buf + 14);
            get_alpha(buf + 18, 4, out.orderbook_id);
            get_alpha(buf + 22, 4, out.group);
            out.price = be_get_u32(buf + 26);
            if (type == 'F') {
                get_alpha(buf + 30, 4, out.attribution);
                out.order_type = static_cast<char>(buf[34]);
            }
            break;
        case 'E':
            out.ns = be_get_u32(buf + 1);
            out.order_number = be_get_u64(buf + 5);
            out.executed_qty = be_get_u32(buf + 13);
            out.match_number = be_get_u64(buf + 17);
            break;
        case 'D':
            out.ns = be_get_u32(buf + 1);
            out.order_number = be_get_u64(buf + 5);
            break;
        case 'U':
            out.ns = be_get_u32(buf + 1);
            out.orig_order_number = be_get_u64(buf + 5);
            out.new_order_number = be_get_u64(buf + 13);
            out.qty = be_get_u32(buf + 21);
            out.price = be_get_u32(buf + 25);
            break;
        case 'G':
            out.sequence_number = be_get_u64(buf + 1);
            break;
        default:
            if (err != NULL) *err = "unknown message type";
            return false;
    }
    return true;
}

size_t encode(const ItchMsg& msg, unsigned char* buf) {
    int want = expected_len(msg.type);
    if (want < 0) {
        return 0;
    }
    buf[0] = static_cast<unsigned char>(msg.type);
    switch (msg.type) {
        case 'T':
            be_put_u32(buf + 1, msg.seconds);
            break;
        case 'S':
            be_put_u32(buf + 1, msg.ns);
            put_alpha(buf + 5, 4, msg.group);
            buf[9] = static_cast<unsigned char>(msg.event);
            break;
        case 'L':
            be_put_u32(buf + 1, msg.ns);
            be_put_u32(buf + 5, msg.tick_table_id);
            be_put_u32(buf + 9, msg.tick_size);
            be_put_u32(buf + 13, msg.price_start);
            break;
        case 'R':
            be_put_u32(buf + 1, msg.ns);
            put_alpha(buf + 5, 4, msg.orderbook_id);
            put_alpha(buf + 9, 12, msg.isin);
            put_alpha(buf + 21, 4, msg.group);
            be_put_u32(buf + 25, msg.round_lot);
            be_put_u32(buf + 29, msg.tick_table_id);
            be_put_u32(buf + 33, msg.price_decimals);
            be_put_u32(buf + 37, msg.upper_limit);
            be_put_u32(buf + 41, msg.lower_limit);
            break;
        case 'H':
        case 'Y':
            be_put_u32(buf + 1, msg.ns);
            put_alpha(buf + 5, 4, msg.orderbook_id);
            put_alpha(buf + 9, 4, msg.group);
            buf[13] = static_cast<unsigned char>(msg.state);
            break;
        case 'A':
        case 'F':
            be_put_u32(buf + 1, msg.ns);
            be_put_u64(buf + 5, msg.order_number);
            buf[13] = static_cast<unsigned char>(msg.side);
            be_put_u32(buf + 14, msg.qty);
            put_alpha(buf + 18, 4, msg.orderbook_id);
            put_alpha(buf + 22, 4, msg.group);
            be_put_u32(buf + 26, msg.price);
            if (msg.type == 'F') {
                put_alpha(buf + 30, 4, msg.attribution);
                buf[34] = static_cast<unsigned char>(msg.order_type);
            }
            break;
        case 'E':
            be_put_u32(buf + 1, msg.ns);
            be_put_u64(buf + 5, msg.order_number);
            be_put_u32(buf + 13, msg.executed_qty);
            be_put_u64(buf + 17, msg.match_number);
            break;
        case 'D':
            be_put_u32(buf + 1, msg.ns);
            be_put_u64(buf + 5, msg.order_number);
            break;
        case 'U':
            be_put_u32(buf + 1, msg.ns);
            be_put_u64(buf + 5, msg.orig_order_number);
            be_put_u64(buf + 13, msg.new_order_number);
            be_put_u32(buf + 21, msg.qty);
            be_put_u32(buf + 25, msg.price);
            break;
        case 'G':
            be_put_u64(buf + 1, msg.sequence_number);
            break;
        default:
            return 0;
    }
    return static_cast<size_t>(want);
}

} // namespace jnx

// soup.h — SoupBinTCP packet codec + incremental stream framer.
//
// Wire format (JNX_PLAN.md §3.4): logical packet =
//   length:2:num (big-endian, EXCLUDES the length field itself)
//   + type:1:char + payload.
//
// Packet types:
//   server->client: 'A' LoginAccepted, 'J' LoginRejected, 'S' SequencedData,
//                   'H' server heartbeat, 'Z' EndOfSession, '+' Debug
//   client->server: 'L' LoginRequest, 'U' UnsequencedData,
//                   'R' client heartbeat, 'O' LogoutRequest
//
// Padding rules (pinned by the golden vectors):
//   LoginRequest:  username(6)/password(10) RIGHT-padded with spaces;
//                  requested_session(10) and requested_sequence(20, ASCII
//                  digits) LEFT-padded with spaces.
//   LoginAccepted: session(10) and sequence(20, ASCII digits) LEFT-padded
//                  with spaces.
#ifndef JNX_SOUP_H
#define JNX_SOUP_H

#include <cstddef>
#include <cstdint>
#include <vector>

namespace jnx {

// One framed logical packet. `payload` is the bytes after the type char
// (owned copy — valid independent of the framer; simplicity first).
struct SoupPacket {
    char type;
    std::vector<unsigned char> payload;

    SoupPacket() : type('\0') {}
};

// --- typed payload structs (fields host-order / stripped strings) -------

struct SoupLoginRequest {
    char username[7];           // <= 6 chars
    char password[11];          // <= 10 chars
    char requested_session[11]; // <= 10 chars ("" = current session)
    uint64_t requested_sequence;

    SoupLoginRequest() : requested_sequence(0) {
        username[0] = '\0';
        password[0] = '\0';
        requested_session[0] = '\0';
    }
};

struct SoupLoginAccepted {
    char session[11]; // <= 10 chars
    uint64_t sequence;

    SoupLoginAccepted() : sequence(0) { session[0] = '\0'; }
};

struct SoupLoginRejected {
    char reject_code; // 'A' not authorized, 'S' session unavailable

    SoupLoginRejected() : reject_code('\0') {}
};

// --- payload parsers (from SoupPacket.payload) ---------------------------
// Return false + static *err on wrong payload length / non-numeric seq.

bool soup_parse_login_request(const unsigned char* payload, size_t len,
                              SoupLoginRequest& out, const char** err);
bool soup_parse_login_accepted(const unsigned char* payload, size_t len,
                               SoupLoginAccepted& out, const char** err);
bool soup_parse_login_rejected(const unsigned char* payload, size_t len,
                               SoupLoginRejected& out, const char** err);

// --- packet builders ------------------------------------------------------
// Each writes a COMPLETE wire packet (2-byte length prefix + type +
// payload) into buf and returns total bytes written. Callers size buf via
// the constants below (payload-carrying builders need 3 + payload_len).

const size_t SOUP_LOGIN_REQUEST_WIRE = 2 + 1 + 6 + 10 + 10 + 20; // 49
const size_t SOUP_LOGIN_ACCEPTED_WIRE = 2 + 1 + 10 + 20;         // 33
const size_t SOUP_LOGIN_REJECTED_WIRE = 2 + 1 + 1;               // 4
const size_t SOUP_BARE_WIRE = 2 + 1; // heartbeats / logout / end-of-session

size_t soup_build_login_request(const SoupLoginRequest& in,
                                unsigned char* buf);
size_t soup_build_login_accepted(const SoupLoginAccepted& in,
                                 unsigned char* buf);
size_t soup_build_login_rejected(const SoupLoginRejected& in,
                                 unsigned char* buf);
// Generic builder for payload-carrying ('S','U','+') and bare
// ('H','Z','R','O') packets. payload may be NULL when payload_len == 0.
size_t soup_build_packet(char type, const unsigned char* payload,
                         size_t payload_len, unsigned char* buf);

// --- stream framer --------------------------------------------------------
// Incremental: tolerates byte-at-a-time input and a length prefix split
// across feed() calls. Packets are returned in order via next(), which
// copies the payload into the caller's SoupPacket (the returned packet
// stays valid after further feed()/next() calls).
class SoupFramer {
public:
    SoupFramer() : bad_frames_(0) {}

    void feed(const unsigned char* data, size_t len);

    // Extracts the next complete packet; returns false if none buffered.
    bool next(SoupPacket& out);

    // Count of malformed frames skipped (declared length 0 — a packet must
    // contain at least the type char).
    uint64_t bad_frames() const { return bad_frames_; }

private:
    std::vector<unsigned char> buf_;
    uint64_t bad_frames_;
};

} // namespace jnx

#endif // JNX_SOUP_H

// soup.cpp — see soup.h.
#include "soup/soup.h"

#include <cstdio>
#include <cstring>

#include "common/endian.h"

namespace jnx {

namespace {

// Strip leading AND trailing spaces of a fixed-width field into out
// (room for width+1). Soup session fields are left-padded, so leading
// spaces are padding; trailing spaces can't be meaningful either.
void get_padded_str(const unsigned char* p, size_t width, char* out) {
    size_t start = 0;
    while (start < width && p[start] == ' ') {
        ++start;
    }
    size_t end = width;
    while (end > start && p[end - 1] == ' ') {
        --end;
    }
    std::memcpy(out, p + start, end - start);
    out[end - start] = '\0';
}

// Right-pad (left-justify) s into a width-byte field.
void put_right_padded(unsigned char* p, size_t width, const char* s) {
    size_t n = std::strlen(s);
    if (n > width) {
        n = width;
    }
    std::memcpy(p, s, n);
    std::memset(p + n, ' ', width - n);
}

// Left-pad (right-justify) s into a width-byte field.
void put_left_padded(unsigned char* p, size_t width, const char* s) {
    size_t n = std::strlen(s);
    if (n > width) {
        n = width;
    }
    std::memset(p, ' ', width - n);
    std::memcpy(p + (width - n), s, n);
}

// Parse an ASCII-decimal, space-left-padded numeric field. Empty (all
// spaces) is invalid.
bool parse_seq_field(const unsigned char* p, size_t width, uint64_t& out) {
    size_t i = 0;
    while (i < width && p[i] == ' ') {
        ++i;
    }
    if (i == width) {
        return false;
    }
    uint64_t v = 0;
    for (; i < width; ++i) {
        if (p[i] < '0' || p[i] > '9') {
            return false;
        }
        v = v * 10 + static_cast<uint64_t>(p[i] - '0');
    }
    out = v;
    return true;
}

// Render v as ASCII decimal left-padded with spaces into width bytes.
void put_seq_field(unsigned char* p, size_t width, uint64_t v) {
    char tmp[32];
    int n = std::snprintf(tmp, sizeof(tmp), "%llu",
                          static_cast<unsigned long long>(v));
    put_left_padded(p, width, tmp);
    (void)n;
}

} // namespace

bool soup_parse_login_request(const unsigned char* payload, size_t len,
                              SoupLoginRequest& out, const char** err) {
    if (len != 6 + 10 + 10 + 20) {
        if (err != NULL) *err = "LoginRequest payload must be 46 bytes";
        return false;
    }
    get_padded_str(payload, 6, out.username);
    get_padded_str(payload + 6, 10, out.password);
    get_padded_str(payload + 16, 10, out.requested_session);
    if (!parse_seq_field(payload + 26, 20, out.requested_sequence)) {
        if (err != NULL) *err = "LoginRequest bad requested_sequence";
        return false;
    }
    return true;
}

bool soup_parse_login_accepted(const unsigned char* payload, size_t len,
                               SoupLoginAccepted& out, const char** err) {
    if (len != 10 + 20) {
        if (err != NULL) *err = "LoginAccepted payload must be 30 bytes";
        return false;
    }
    get_padded_str(payload, 10, out.session);
    if (!parse_seq_field(payload + 10, 20, out.sequence)) {
        if (err != NULL) *err = "LoginAccepted bad sequence";
        return false;
    }
    return true;
}

bool soup_parse_login_rejected(const unsigned char* payload, size_t len,
                               SoupLoginRejected& out, const char** err) {
    if (len != 1) {
        if (err != NULL) *err = "LoginRejected payload must be 1 byte";
        return false;
    }
    out.reject_code = static_cast<char>(payload[0]);
    return true;
}

size_t soup_build_login_request(const SoupLoginRequest& in,
                                unsigned char* buf) {
    be_put_u16(buf, static_cast<uint16_t>(1 + 46));
    buf[2] = 'L';
    put_right_padded(buf + 3, 6, in.username);
    put_right_padded(buf + 9, 10, in.password);
    put_left_padded(buf + 19, 10, in.requested_session);
    put_seq_field(buf + 29, 20, in.requested_sequence);
    return SOUP_LOGIN_REQUEST_WIRE;
}

size_t soup_build_login_accepted(const SoupLoginAccepted& in,
                                 unsigned char* buf) {
    be_put_u16(buf, static_cast<uint16_t>(1 + 30));
    buf[2] = 'A';
    put_left_padded(buf + 3, 10, in.session);
    put_seq_field(buf + 13, 20, in.sequence);
    return SOUP_LOGIN_ACCEPTED_WIRE;
}

size_t soup_build_login_rejected(const SoupLoginRejected& in,
                                 unsigned char* buf) {
    be_put_u16(buf, static_cast<uint16_t>(1 + 1));
    buf[2] = 'J';
    buf[3] = static_cast<unsigned char>(in.reject_code);
    return SOUP_LOGIN_REJECTED_WIRE;
}

size_t soup_build_packet(char type, const unsigned char* payload,
                         size_t payload_len, unsigned char* buf) {
    be_put_u16(buf, static_cast<uint16_t>(1 + payload_len));
    buf[2] = static_cast<unsigned char>(type);
    if (payload_len > 0) {
        std::memcpy(buf + 3, payload, payload_len);
    }
    return 3 + payload_len;
}

void SoupFramer::feed(const unsigned char* data, size_t len) {
    buf_.insert(buf_.end(), data, data + len);
}

bool SoupFramer::next(SoupPacket& out) {
    for (;;) {
        if (buf_.size() < 2) {
            return false;
        }
        uint16_t plen = be_get_u16(&buf_[0]);
        if (plen == 0) {
            // Malformed: a packet must contain at least the type char.
            // Skip the bogus length prefix and keep scanning.
            ++bad_frames_;
            buf_.erase(buf_.begin(), buf_.begin() + 2);
            continue;
        }
        if (buf_.size() < static_cast<size_t>(2 + plen)) {
            return false;
        }
        out.type = static_cast<char>(buf_[2]);
        out.payload.assign(buf_.begin() + 3, buf_.begin() + 2 + plen);
        buf_.erase(buf_.begin(), buf_.begin() + 2 + plen);
        return true;
    }
}

} // namespace jnx

// jsonvec.h — minimal JSON reader for EXACTLY the golden-vector file shape:
//
//   {"vectors": [{"name": "...", "type": "...", "hex": "...",
//                 "fields": {"k": <int-or-string>, ...}}, ...]}
//
// String values may contain only plain characters (no escapes are used in
// the vector files; an escape fails loudly). Integers are non-negative and
// fit uint64. Anything unexpected -> loud failure (message + false).
// NOT a general JSON parser and never will be. Test-only helper.
#ifndef JNX_JSONVEC_H
#define JNX_JSONVEC_H

#include <cstdint>
#include <cstdio>
#include <fstream>
#include <map>
#include <sstream>
#include <string>
#include <vector>

namespace jsonvec {

struct Vector {
    std::string name;
    std::string type;
    std::string hex;
    std::map<std::string, std::string> str_fields;
    std::map<std::string, uint64_t> int_fields;

    bool has_int(const std::string& k) const {
        return int_fields.find(k) != int_fields.end();
    }
    bool has_str(const std::string& k) const {
        return str_fields.find(k) != str_fields.end();
    }
};

class Parser {
public:
    Parser(const std::string& text) : s_(text), pos_(0) {}

    bool fail(const char* why) {
        std::fprintf(stderr, "jsonvec: parse error at offset %zu: %s\n", pos_,
                     why);
        return false;
    }

    void skip_ws() {
        while (pos_ < s_.size() &&
               (s_[pos_] == ' ' || s_[pos_] == '\t' || s_[pos_] == '\n' ||
                s_[pos_] == '\r')) {
            ++pos_;
        }
    }

    bool expect(char c) {
        skip_ws();
        if (pos_ >= s_.size() || s_[pos_] != c) {
            std::fprintf(stderr,
                         "jsonvec: parse error at offset %zu: expected '%c'\n",
                         pos_, c);
            return false;
        }
        ++pos_;
        return true;
    }

    bool peek(char c) {
        skip_ws();
        return pos_ < s_.size() && s_[pos_] == c;
    }

    bool parse_string(std::string& out) {
        if (!expect('"')) return false;
        out.clear();
        while (pos_ < s_.size() && s_[pos_] != '"') {
            if (s_[pos_] == '\\') {
                return fail("string escapes not supported");
            }
            out.push_back(s_[pos_]);
            ++pos_;
        }
        if (pos_ >= s_.size()) return fail("unterminated string");
        ++pos_; // closing quote
        return true;
    }

    bool parse_uint(uint64_t& out) {
        skip_ws();
        if (pos_ >= s_.size() || s_[pos_] < '0' || s_[pos_] > '9') {
            return fail("expected non-negative integer");
        }
        out = 0;
        while (pos_ < s_.size() && s_[pos_] >= '0' && s_[pos_] <= '9') {
            out = out * 10 + static_cast<uint64_t>(s_[pos_] - '0');
            ++pos_;
        }
        return true;
    }

    // Parses the "fields" object: string or uint values only.
    bool parse_fields(Vector& v) {
        if (!expect('{')) return false;
        if (peek('}')) {
            ++pos_;
            return true;
        }
        for (;;) {
            std::string key;
            skip_ws();
            if (!parse_string(key)) return false;
            if (!expect(':')) return false;
            skip_ws();
            if (peek('"')) {
                std::string sval;
                if (!parse_string(sval)) return false;
                v.str_fields[key] = sval;
            } else {
                uint64_t ival = 0;
                if (!parse_uint(ival)) return false;
                v.int_fields[key] = ival;
            }
            skip_ws();
            if (peek(',')) {
                ++pos_;
                continue;
            }
            return expect('}');
        }
    }

    bool parse_vector(Vector& v) {
        if (!expect('{')) return false;
        for (;;) {
            std::string key;
            skip_ws();
            if (!parse_string(key)) return false;
            if (!expect(':')) return false;
            skip_ws();
            if (key == "name") {
                if (!parse_string(v.name)) return false;
            } else if (key == "type") {
                if (!parse_string(v.type)) return false;
            } else if (key == "hex") {
                if (!parse_string(v.hex)) return false;
            } else if (key == "fields") {
                if (!parse_fields(v)) return false;
            } else {
                return fail("unexpected key in vector object");
            }
            skip_ws();
            if (peek(',')) {
                ++pos_;
                continue;
            }
            return expect('}');
        }
    }

    bool parse_file(std::vector<Vector>& out) {
        if (!expect('{')) return false;
        std::string key;
        if (!parse_string(key)) return false;
        if (key != "vectors") return fail("expected top-level key 'vectors'");
        if (!expect(':')) return false;
        if (!expect('[')) return false;
        if (peek(']')) {
            ++pos_;
        } else {
            for (;;) {
                Vector v;
                if (!parse_vector(v)) return false;
                out.push_back(v);
                skip_ws();
                if (peek(',')) {
                    ++pos_;
                    continue;
                }
                if (!expect(']')) return false;
                break;
            }
        }
        if (!expect('}')) return false;
        skip_ws();
        if (pos_ != s_.size()) return fail("trailing garbage after document");
        return true;
    }

private:
    const std::string& s_;
    size_t pos_;
};

// Loads a vector file; returns false (after printing why) on any problem.
inline bool load(const std::string& path, std::vector<Vector>& out) {
    std::ifstream in(path.c_str());
    if (!in.is_open()) {
        std::fprintf(stderr, "jsonvec: cannot open %s\n", path.c_str());
        return false;
    }
    std::ostringstream ss;
    ss << in.rdbuf();
    std::string text = ss.str();
    Parser p(text);
    return p.parse_file(out);
}

// Hex string -> bytes. Returns false on odd length / non-hex chars.
inline bool hex_to_bytes(const std::string& hex,
                         std::vector<unsigned char>& out) {
    if (hex.size() % 2 != 0) {
        std::fprintf(stderr, "jsonvec: odd-length hex string\n");
        return false;
    }
    out.clear();
    out.reserve(hex.size() / 2);
    for (size_t i = 0; i < hex.size(); i += 2) {
        unsigned v = 0;
        for (size_t j = 0; j < 2; ++j) {
            char c = hex[i + j];
            v <<= 4;
            if (c >= '0' && c <= '9') {
                v |= static_cast<unsigned>(c - '0');
            } else if (c >= 'a' && c <= 'f') {
                v |= static_cast<unsigned>(c - 'a' + 10);
            } else if (c >= 'A' && c <= 'F') {
                v |= static_cast<unsigned>(c - 'A' + 10);
            } else {
                std::fprintf(stderr, "jsonvec: bad hex char '%c'\n", c);
                return false;
            }
        }
        out.push_back(static_cast<unsigned char>(v));
    }
    return true;
}

} // namespace jsonvec

#endif // JNX_JSONVEC_H

// test_itch.cpp — ITCH codec vs the committed golden vectors
