TEST(itch_truncated_buffers_rejected) {
    // Build valid A and E messages, then try every truncated length.
    jnx::ItchMsg a;
    a.type = 'A';
    a.ns = 1;
    a.order_number = 42;
    a.side = 'B';
    a.qty = 100;
    std::snprintf(a.orderbook_id, sizeof(a.orderbook_id), "8306");
    std::snprintf(a.group, sizeof(a.group), "DAY");
    a.price = 15000;
    unsigned char abuf[64];
    size_t alen = jnx::encode(a, abuf);
    CHECK_EQ(alen, static_cast<size_t>(30));
    for (size_t len = 0; len < alen; ++len) {
        jnx::ItchMsg out;
        const char* err = NULL;
        CHECK(!jnx::decode(abuf, len, out, &err));
        CHECK(err != NULL);
    }

    jnx::ItchMsg e;
    e.type = 'E';
    e.ns = 2;
    e.order_number = 42;
    e.executed_qty = 10;
    e.match_number = 7;
    unsigned char ebuf[64];
    size_t elen = jnx::encode(e, ebuf);
    CHECK_EQ(elen, static_cast<size_t>(25));
    for (size_t len = 0; len < elen; ++len) {
        jnx::ItchMsg out;
        const char* err = NULL;
        CHECK(!jnx::decode(ebuf, len, out, &err));
        CHECK(err != NULL);
    }

    // Over-long buffers must be rejected too (strict length).
    jnx::ItchMsg out;
    const char* err = NULL;
    CHECK(!jnx::decode(abuf, alen + 1, out, &err));
}

TEST(itch_unknown_type_rejected) {
    unsigned char buf[16];
    std::memset(buf, 0, sizeof(buf));
    buf[0] = 'X';
    jnx::ItchMsg out;
    const char* err = NULL;
    CHECK(!jnx::decode(buf, 5, out, &err));
    CHECK(err != NULL);
}

TEST(itch_no_price_roundtrip_untouched) {
    // Reference-price A with the NO_PRICE sentinel must decode as a plain
    // A (order_number 0 carries no special casing at codec level) and the
    // sentinel must survive encode/decode bit-exact.
    jnx::ItchMsg a;
    a.type = 'A';
    a.ns = 123;
    a.order_number = 0; // ref-price carrier — still a normal decode
    a.side = 'B';
    a.qty = 0;
    std::snprintf(a.orderbook_id, sizeof(a.orderbook_id), "8306");
    std::snprintf(a.group, sizeof(a.group), "DAY");
    a.price = jnx::NO_PRICE;
    unsigned char buf[64];
    size_t n = jnx::encode(a, buf);
    CHECK_EQ(n, static_cast<size_t>(30));
    jnx::ItchMsg out;
    const char* err = NULL;
    CHECK(jnx::decode(buf, n, out, &err));
    CHECK_EQ(out.price, jnx::NO_PRICE);
    CHECK_EQ(out.order_number, static_cast<uint64_t>(0));
    CHECK_EQ(std::string(1, out.type), std::string("A"));
}

// test_soup.cpp — SoupBinTCP codec + framer vs the committed golden
// vectors (cpp/test/vectors/soup.json), including byte-at-a-time and
// split-length-prefix framing.
#include "soup/soup.h"

#include <cstring>
#include <string>
#include <vector>

#include "common/minitest.h"
#include "test/jsonvec.h"

namespace {

std::string vectors_path() {
    std::ifstream probe("test/vectors/soup.json");
    if (probe.is_open()) {
        return "test/vectors/soup.json";
    }
    return "cpp/test/vectors/soup.json";
}

bool bytes_equal(const std::vector<unsigned char>& a,
                 const std::vector<unsigned char>& b) {
    return a.size() == b.size() &&
           (a.empty() || std::memcmp(&a[0], &b[0], a.size()) == 0);
}

// Decode one packet's fields and compare against the vector; encode from
// the vector's fields and compare against the golden bytes.
void check_packet_against_vector(const jsonvec::Vector& v,
                                 const jnx::SoupPacket& pkt,
                                 const std::vector<unsigned char>& wire,
                                 int& jnx_failures) {
    CHECK_EQ(std::string(1, pkt.type), v.type);

    const char* err = NULL;
    unsigned char out[128];
    const unsigned char* payload = pkt.payload.empty() ? NULL : &pkt.payload[0];

    if (v.type == "L") {
        jnx::SoupLoginRequest lr;
        CHECK(jnx::soup_parse_login_request(payload, pkt.payload.size(), lr,
                                            &err));
        CHECK_EQ(std::string(lr.username), v.str_fields.at("username"));
        CHECK_EQ(std::string(lr.password), v.str_fields.at("password"));
        CHECK_EQ(std::string(lr.requested_session),
                 v.str_fields.at("requested_session"));
        CHECK_EQ(lr.requested_sequence, v.int_fields.at("requested_sequence"));
        size_t n = jnx::soup_build_login_request(lr, out);
        CHECK_EQ(n, wire.size());
        CHECK(n == wire.size() && std::memcmp(out, &wire[0], n) == 0);
    } else if (v.type == "A") {
        jnx::SoupLoginAccepted la;
        CHECK(jnx::soup_parse_login_accepted(payload, pkt.payload.size(), la,
                                             &err));
        CHECK_EQ(std::string(la.session), v.str_fields.at("session"));
        CHECK_EQ(la.sequence, v.int_fields.at("sequence"));
        size_t n = jnx::soup_build_login_accepted(la, out);
        CHECK_EQ(n, wire.size());
        CHECK(n == wire.size() && std::memcmp(out, &wire[0], n) == 0);
    } else if (v.type == "J") {
        jnx::SoupLoginRejected rj;
        CHECK(jnx::soup_parse_login_rejected(payload, pkt.payload.size(), rj,
                                             &err));
        CHECK_EQ(std::string(1, rj.reject_code),
                 v.str_fields.at("reject_code"));
        size_t n = jnx::soup_build_login_rejected(rj, out);
        CHECK_EQ(n, wire.size());
        CHECK(n == wire.size() && std::memcmp(out, &wire[0], n) == 0);
    } else {
        // Payload-carrying (S/+/U) or bare (H/Z/R/O) packets: compare the
        // payload against the vector's hex field (if any), then rebuild.
        std::string key;
        if (v.has_str("payload_hex")) key = "payload_hex";
        else if (v.has_str("message_hex")) key = "message_hex";
        std::vector<unsigned char> want_payload;
        if (!key.empty()) {
            CHECK(jsonvec::hex_to_bytes(v.str_fields.at(key), want_payload));
        }
        CHECK(bytes_equal(pkt.payload, want_payload));
        size_t n = jnx::soup_build_packet(pkt.type, payload,
                                          pkt.payload.size(), out);
        CHECK_EQ(n, wire.size());
        CHECK(n == wire.size() && std::memcmp(out, &wire[0], n) == 0);
    }
}

} // namespace

TEST(soup_golden_vectors_whole_packet) {
    std::vector<jsonvec::Vector> vecs;
    CHECK(jsonvec::load(vectors_path(), vecs));
    CHECK_EQ(vecs.size(), static_cast<size_t>(16));
    for (size_t i = 0; i < vecs.size(); ++i) {
        const jsonvec::Vector& v = vecs[i];
        std::vector<unsigned char> wire;
        CHECK(jsonvec::hex_to_bytes(v.hex, wire));

        jnx::SoupFramer framer;
        framer.feed(&wire[0], wire.size());
        jnx::SoupPacket pkt;
        bool got = framer.next(pkt);
        if (!got) {
            std::fprintf(stderr, "  vector %s: framer produced no packet\n",
                         v.name.c_str());
        }
        CHECK(got);
        if (!got) continue;
        check_packet_against_vector(v, pkt, wire, jnx_failures);
        // Nothing left over.
        CHECK(!framer.next(pkt));
        CHECK_EQ(framer.bad_frames(), static_cast<uint64_t>(0));
    }
}

TEST(soup_golden_vectors_byte_at_a_time) {
    std::vector<jsonvec::Vector> vecs;
    CHECK(jsonvec::load(vectors_path(), vecs));
    for (size_t i = 0; i < vecs.size(); ++i) {
        const jsonvec::Vector& v = vecs[i];
        std::vector<unsigned char> wire;
        CHECK(jsonvec::hex_to_bytes(v.hex, wire));

        jnx::SoupFramer framer;
        jnx::SoupPacket pkt;
        // Until the last byte arrives, no packet may be produced.
        for (size_t j = 0; j + 1 < wire.size(); ++j) {
            framer.feed(&wire[j], 1);
            CHECK(!framer.next(pkt));
        }
        framer.feed(&wire[wire.size() - 1], 1);
        bool got = framer.next(pkt);
        CHECK(got);
        if (got) {
            check_packet_against_vector(v, pkt, wire, jnx_failures);
        }
    }
}

TEST(soup_split_length_prefix_and_back_to_back) {
    // Two packets concatenated, delivered with the second packet's length
    // prefix split across feeds.
    std::vector<jsonvec::Vector> vecs;
    CHECK(jsonvec::load(vectors_path(), vecs));
    // Use the first two vectors (login request + typical login request).
    std::vector<unsigned char> w1, w2;
    CHECK(jsonvec::hex_to_bytes(vecs[0].hex, w1));
    CHECK(jsonvec::hex_to_bytes(vecs[1].hex, w2));

    std::vector<unsigned char> stream(w1);
    stream.insert(stream.end(), w2.begin(), w2.end());

    jnx::SoupFramer framer;
    // Feed everything up to and including the FIRST byte of packet 2's
    // length prefix, then the rest.
    size_t cut = w1.size() + 1;
    framer.feed(&stream[0], cut);
    jnx::SoupPacket p1;
    CHECK(framer.next(p1));
    check_packet_against_vector(vecs[0], p1, w1, jnx_failures);
    jnx::SoupPacket p2;
    CHECK(!framer.next(p2)); // second packet incomplete (half a prefix)
    framer.feed(&stream[cut], stream.size() - cut);
    CHECK(framer.next(p2));
    check_packet_against_vector(vecs[1], p2, w2, jnx_failures);
    CHECK(!framer.next(p2));
}

TEST(soup_zero_length_frame_skipped) {
    // A zero length prefix is malformed (a packet has at least the type
    // char); the framer must count and skip it, then resume.
    unsigned char bogus[2] = {0x00, 0x00};
    unsigned char hb[3] = {0x00, 0x01, 'H'};
    jnx::SoupFramer framer;
    framer.feed(bogus, 2);
    framer.feed(hb, 3);
    jnx::SoupPacket pkt;
    CHECK(framer.next(pkt));
    CHECK_EQ(std::string(1, pkt.type), std::string("H"));
    CHECK_EQ(pkt.payload.size(), static_cast<size_t>(0));
    CHECK_EQ(framer.bad_frames(), static_cast<uint64_t>(1));
}

// itch_replay — decode every message in an ITCH Binary Data File
// (JNX_PLAN.md §3.7: repeated `length:2:BE + ITCH message`) and print one
// summary line:
//   total=N  A=.. E=.. ...  errors=K
// Per-type counts are printed for types seen, in descending count order
// (ties broken by type char). On the first decode error, the file offset
// and reason are printed to stderr. Exit code: 0 if errors==0, else 1.
#include <cstdio>
#include <cstring>
#include <algorithm>
#include <string>
#include <vector>

#include "itch/itch.h"

int main(int argc, char** argv) {
    if (argc != 2) {
        std::fprintf(stderr, "usage: itch_replay <file.itch>\n");
        return 2;
    }
    std::FILE* f = std::fopen(argv[1], "rb");
    if (f == NULL) {
        std::fprintf(stderr, "itch_replay: cannot open %s\n", argv[1]);
        return 2;
    }

    uint64_t total = 0;
    uint64_t errors = 0;
    uint64_t counts[256];
    std::memset(counts, 0, sizeof(counts));
    bool first_error_reported = false;
    unsigned long long offset = 0;
    unsigned char lenbuf[2];
    unsigned char msgbuf[65536];

    for (;;) {
        size_t got = std::fread(lenbuf, 1, 2, f);
        if (got == 0) {
            break; // clean EOF
        }
        if (got != 2) {
            std::fprintf(stderr,
                         "itch_replay: truncated length prefix at offset "
                         "%llu\n",
                         offset);
            ++errors;
            break;
        }
        size_t mlen = (static_cast<size_t>(lenbuf[0]) << 8) |
                      static_cast<size_t>(lenbuf[1]);
        offset += 2;
        if (mlen == 0) {
            std::fprintf(stderr,
                         "itch_replay: zero-length message at offset %llu\n",
                         offset);
            ++errors;
            break;
        }
        if (std::fread(msgbuf, 1, mlen, f) != mlen) {
            std::fprintf(stderr,
                         "itch_replay: truncated message at offset %llu\n",
                         offset);
            ++errors;
            break;
        }
        ++total;
        jnx::ItchMsg msg;
        const char* err = NULL;
        if (jnx::decode(msgbuf, mlen, msg, &err)) {
            ++counts[static_cast<unsigned char>(msg.type)];
        } else {
            ++errors;
            if (!first_error_reported) {
                first_error_reported = true;
                std::fprintf(stderr,
                             "itch_replay: first decode error at offset "
                             "%llu (type 0x%02x len %zu): %s\n",
                             offset, msgbuf[0], mlen, err ? err : "?");
            }
        }
        offset += mlen;
    }
    std::fclose(f);

    // Collect seen types, descending count (ties by type char).
    std::vector<std::pair<uint64_t, char> > seen;
    for (int c = 0; c < 256; ++c) {
        if (counts[c] > 0) {
            seen.push_back(std::make_pair(counts[c], static_cast<char>(c)));
        }
    }
    struct ByCountDesc {
        bool operator()(const std::pair<uint64_t, char>& a,
                        const std::pair<uint64_t, char>& b) const {
            if (a.first != b.first) return a.first > b.first;
            return a.second < b.second;
        }
    };
    std::sort(seen.begin(), seen.end(), ByCountDesc());

    std::printf("total=%llu ", static_cast<unsigned long long>(total));
    for (size_t i = 0; i < seen.size(); ++i) {
        std::printf(" %c=%llu", seen[i].second,
                    static_cast<unsigned long long>(seen[i].first));
    }
    std::printf("  errors=%llu\n", static_cast<unsigned long long>(errors));
    return errors == 0 ? 0 : 1;
}

