// refdata.h — reference data store: C++ port of jnxfeed/book/refdata.py.
//
// Consumes R / L / H / Y / S and reference-price A (order_number == 0).
// Absence semantics (JNX_PLAN.md §3.3(4)): default trading_state 'V'
// (suspended), default short_sell_state '0' (unrestricted). Auto-create
// (§3.3(5)): first reference to an unknown orderbook id creates a record
// flagged directory_missing until an R describes it.
//
// "None" representation (prototype uses Python None): numeric fields use
// int64_t -1; string fields use "".
#ifndef JNX_MARKET_REFDATA_H
#define JNX_MARKET_REFDATA_H

#include <cstdint>
#include <map>
#include <string>
#include <vector>

#include "itch/itch.h"

namespace jnx {

struct Instrument {
    std::string orderbook_id;
    std::string isin;  // "" = unknown
    std::string group; // "" = unknown
    int64_t round_lot;      // -1 = unknown
    int64_t tick_table_id;  // -1 = unknown
    int64_t price_decimals; // -1 = unknown
    int64_t upper_limit;    // -1 = unknown
    int64_t lower_limit;    // -1 = unknown
    char trading_state;     // default 'V' (absence = suspended)
    char short_sell_state;  // default '0' (absence = unrestricted)
    int64_t reference_price; // -1 = no ref-price A seen (NO_PRICE is valid)
    bool directory_missing;  // true until an R arrives

    Instrument()
        : round_lot(-1),
          tick_table_id(-1),
          price_decimals(-1),
          upper_limit(-1),
          lower_limit(-1),
          trading_state('V'),
          short_sell_state('0'),
          reference_price(-1),
          directory_missing(true) {}
};

// One tick-size table from L rows: tick_size applies from price_start
// (inclusive) to the next row's start (exclusive). Duplicate price_start
// replaces the row.
class TickTable {
public:
    void add(uint32_t price_start, uint32_t tick_size) {
        rows_[price_start] = tick_size;
    }

    // Tick size in effect at price; false if below every row / empty.
    bool tick_size(uint32_t price, uint32_t& out) const {
        std::map<uint32_t, uint32_t>::const_iterator it =
            rows_.upper_bound(price);
        if (it == rows_.begin()) {
            return false;
        }
        --it;
        out = it->second;
        return true;
    }

    const std::map<uint32_t, uint32_t>& rows() const { return rows_; }

private:
    std::map<uint32_t, uint32_t> rows_; // price_start -> tick_size
};

struct SystemEvent {
    uint32_t ns;
    std::string group; // "" = system-wide
    char event;
};

class RefData {
public:
    // Instrument for orderbook_id, auto-creating a directory_missing
    // record on first reference.
    Instrument& get(const std::string& orderbook_id);

    TickTable& tick_table(uint32_t tick_table_id) {
        return tick_tables_[tick_table_id];
    }

    // Applies one decoded message; returns true if consumed (R/L/H/Y/S or
    // ref-price A), false if it is not a refdata concern.
    bool apply(const ItchMsg& msg);

    const std::map<std::string, Instrument>& instruments() const {
        return instruments_;
    }
    const std::map<uint32_t, TickTable>& tick_tables() const {
        return tick_tables_;
    }
    const std::vector<SystemEvent>& system_events() const {
        return system_events_;
    }

private:
    std::map<std::string, Instrument> instruments_;
    std::map<uint32_t, TickTable> tick_tables_;
    std::vector<SystemEvent> system_events_;
};

} // namespace jnx

#endif // JNX_MARKET_REFDATA_H

// refdata.cpp — see refdata.h.
#include "market/refdata.h"

namespace jnx {

Instrument& RefData::get(const std::string& orderbook_id) {
    std::map<std::string, Instrument>::iterator it =
        instruments_.find(orderbook_id);
    if (it == instruments_.end()) {
        Instrument inst;
        inst.orderbook_id = orderbook_id;
        it = instruments_.insert(std::make_pair(orderbook_id, inst)).first;
    }
    return it->second;
}

bool RefData::apply(const ItchMsg& msg) {
    switch (msg.type) {
        case 'R': {
            Instrument& inst = get(msg.orderbook_id);
            inst.isin = msg.isin;
            inst.group = msg.group;
            inst.round_lot = static_cast<int64_t>(msg.round_lot);
            inst.tick_table_id = static_cast<int64_t>(msg.tick_table_id);
            inst.price_decimals = static_cast<int64_t>(msg.price_decimals);
            inst.upper_limit = static_cast<int64_t>(msg.upper_limit);
            inst.lower_limit = static_cast<int64_t>(msg.lower_limit);
            inst.directory_missing = false;
            return true;
        }
        case 'L':
            tick_table(msg.tick_table_id).add(msg.price_start, msg.tick_size);
            return true;
        case 'H': {
            Instrument& inst = get(msg.orderbook_id);
            if (inst.group.empty()) {
                inst.group = msg.group;
            }
            inst.trading_state = msg.state;
            return true;
        }
        case 'Y': {
            Instrument& inst = get(msg.orderbook_id);
            if (inst.group.empty()) {
                inst.group = msg.group;
            }
            inst.short_sell_state = msg.state;
            return true;
        }
        case 'S': {
            SystemEvent ev;
            ev.ns = msg.ns;
            ev.group = msg.group;
            ev.event = msg.event;
            system_events_.push_back(ev);
            return true;
        }
        case 'A':
            if (msg.order_number == 0) {
                // Reference-price update (§3.3(1)): NOT an order; price
                // may be NO_PRICE; side/qty meaningless.
                Instrument& inst = get(msg.orderbook_id);
                if (inst.group.empty()) {
                    inst.group = msg.group;
                }
                inst.reference_price = static_cast<int64_t>(msg.price);
                return true;
            }
            return false;
        default:
            return false;
    }
}

} // namespace jnx

// levels.h — price-aggregated levels for one order book, both sides.
// C++ port of jnxfeed/book/orderbook.py _SideLevels/Book (qty per price;
// the prototype tracks NO per-level order count — order counts are derived
// from the order store by consumers that need them).
#ifndef JNX_MARKET_LEVELS_H
#define JNX_MARKET_LEVELS_H

#include <cstdint>
#include <functional>
#include <map>
#include <string>

namespace jnx {

// Aggregated qty per price for one side. Kept ascending (like the
// prototype's sorted list); Book's accessors present bids best-first by
// reverse iteration.
class SideLevels {
public:
    // Aggregate qty as uint64: individual qtys are u32 but a level's sum
    // may exceed it.
    typedef std::map<uint32_t, uint64_t> LevelMap;

    void add(uint32_t price, uint32_t qty);

    // Removes qty from the price level; erases the level at exactly zero.
    // Returns false if the level would go negative (a logic error — the
    // store clamps executions so this cannot happen on any input).
    bool remove(uint32_t price, uint32_t qty);

    uint64_t qty_at(uint32_t price) const {
        LevelMap::const_iterator it = levels_.find(price);
        return it == levels_.end() ? 0 : it->second;
    }

    uint64_t total_qty() const;

    size_t size() const { return levels_.size(); }

    // Ascending by price. Bids: iterate in reverse for best-first.
    const LevelMap& ascending() const { return levels_; }

private:
    LevelMap levels_;
};

// Both sides of one order book.
class Book {
public:
    Book() {}
    explicit Book(const std::string& orderbook_id)
        : orderbook_id_(orderbook_id) {}

    const std::string& orderbook_id() const { return orderbook_id_; }

    SideLevels& side(char s) { return s == 'B' ? bids_ : asks_; }
    const SideLevels& bids() const { return bids_; }
    const SideLevels& asks() const { return asks_; }

    void add(char s, uint32_t price, uint32_t qty) {
        side(s).add(price, qty);
    }
    bool remove(char s, uint32_t price, uint32_t qty) {
        return side(s).remove(price, qty);
    }

private:
    std::string orderbook_id_;
    SideLevels bids_;
    SideLevels asks_;
};

} // namespace jnx

#endif // JNX_MARKET_LEVELS_H

// levels.cpp — see levels.h.
#include "market/levels.h"

namespace jnx {

void SideLevels::add(uint32_t price, uint32_t qty) {
    LevelMap::iterator it = levels_.find(price);
    if (it == levels_.end()) {
        levels_[price] = qty;
    } else {
        it->second += qty;
    }
}

bool SideLevels::remove(uint32_t price, uint32_t qty) {
    LevelMap::iterator it = levels_.find(price);
    if (it == levels_.end() || it->second < qty) {
        return false; // would go negative — upstream logic error
    }
    it->second -= qty;
    if (it->second == 0) {
        levels_.erase(it);
    }
    return true;
}

uint64_t SideLevels::total_qty() const {
    uint64_t total = 0;
    for (LevelMap::const_iterator it = levels_.begin(); it != levels_.end();
         ++it) {
        total += it->second;
    }
    return total;
}

} // namespace jnx

// orders.h — order-number-keyed store + per-book aggregated price levels.
// C++ port of jnxfeed/book/orderbook.py OrderBookStore, with identical
// semantics and counter behavior:
//
// - A/F insert (ref-price A with order_number==0 is counted as
//   ref_price_ignored and dropped — it belongs to refdata; Market routes
//   it there and never calls the store with it).
// - E resolves the stored passive order; trade price = the STORED order's
//   price; executions are cumulative; executed_qty > remaining clamps to
//   remaining (counted); order erased at exactly zero remaining.
// - D erases; unknown order number = orphan (counted, ignored).
// - U erases the original and inserts the new order inheriting
//   orderbook_id/group/side from the ORIGINAL, price/qty from the message.
//   Unknown original = orphan; the new order is NOT inserted.
// - Insert over an already-live order number = collision: counted, the
//   stale order is removed (store + levels) and replaced.
#ifndef JNX_MARKET_ORDERS_H
#define JNX_MARKET_ORDERS_H

#include <cstdint>
#include <map>
#include <string>
#include <unordered_map>

#include "itch/itch.h"
#include "market/levels.h"

namespace jnx {

struct Order {
    uint64_t order_number;
    std::string orderbook_id;
    std::string group;
    char side; // 'B'/'S'
    uint32_t price;
    uint32_t remaining_qty;

    Order() : order_number(0), side('\0'), price(0), remaining_qty(0) {}
};

// One fill derived from an E against the stored passive order. side/price
// are the PASSIVE order's (§3.3(2)).
struct Execution {
    std::string orderbook_id;
    std::string group;
    char side;
    uint32_t price;
    uint32_t qty; // clamped executed qty
    uint64_t match_number;

    Execution() : side('\0'), price(0), qty(0), match_number(0) {}
};

class OrderBookStore {
public:
    OrderBookStore()
        : collisions(0),
          orphan_executes(0),
          orphan_deletes(0),
          orphan_replaces(0),
          ref_price_ignored(0),
          clamped_executions(0),
          executed_volume(0),
          execution_count(0) {}

    // Applies one book message (A/F/E/D/U). For an E matched against a
    // known order fills `execution` and returns true; everything else
    // returns false (including consumed A/F/D/U). Non-book types are a
    // no-op (Market routes; passing anything else here does nothing).
    bool apply(const ItchMsg& msg, Execution& execution);

    // The Book for orderbook_id, auto-created on first use (mirrors the
    // prototype: books exist once an order touched them).
    Book& book(const std::string& orderbook_id);

    const std::unordered_map<uint64_t, Order>& orders() const {
        return orders_;
    }
    const std::map<std::string, Book>& books() const { return books_; }
    size_t live_order_count() const { return orders_.size(); }
    uint64_t orphans_total() const {
        return orphan_executes + orphan_deletes + orphan_replaces;
    }

    // Diagnostics (public, mirroring the prototype's attributes).
    uint64_t collisions;        // insert over an already-live number
    uint64_t orphan_executes;   // E referencing an unknown order number
    uint64_t orphan_deletes;    // D referencing an unknown order number
    uint64_t orphan_replaces;   // U referencing an unknown orig number
    uint64_t ref_price_ignored; // ref-price A misrouted here
    uint64_t clamped_executions; // E with executed_qty > remaining
    uint64_t executed_volume;   // total qty across all executions
    uint64_t execution_count;

private:
    void insert(uint64_t order_number, const std::string& orderbook_id,
                const std::string& group, char side, uint32_t price,
                uint32_t qty);
    void remove_order(const Order& order);
    bool execute(const ItchMsg& msg, Execution& execution);
    void erase(const ItchMsg& msg);
    void replace(const ItchMsg& msg);

    std::unordered_map<uint64_t, Order> orders_;
    // std::map so every iteration (dumps!) is deterministically sorted.
    std::map<std::string, Book> books_;
};

} // namespace jnx

#endif // JNX_MARKET_ORDERS_H

// orders.cpp — see orders.h. Mirrors jnxfeed/book/orderbook.py exactly.
#include "market/orders.h"

#include "common/log.h"

namespace jnx {

Book& OrderBookStore::book(const std::string& orderbook_id) {
    std::map<std::string, Book>::iterator it = books_.find(orderbook_id);
    if (it == books_.end()) {
        it = books_.insert(std::make_pair(orderbook_id, Book(orderbook_id)))
                 .first;
    }
    return it->second;
}

bool OrderBookStore::apply(const ItchMsg& msg, Execution& execution) {
    switch (msg.type) {
        case 'A':
        case 'F':
            if (msg.order_number == 0) {
                // Reference-price pseudo-order (§3.3(1)) — refdata's
                // business. Count so misrouting shows up.
                ++ref_price_ignored;
                return false;
            }
            insert(msg.order_number, msg.orderbook_id, msg.group, msg.side,
                   msg.price, msg.qty);
            return false;
        case 'E':
            return execute(msg, execution);
        case 'D':
            erase(msg);
            return false;
        case 'U':
            replace(msg);
            return false;
        default:
            return false;
    }
}

void OrderBookStore::insert(uint64_t order_number,
                            const std::string& orderbook_id,
                            const std::string& group, char side,
                            uint32_t price, uint32_t qty) {
    std::unordered_map<uint64_t, Order>::iterator it =
        orders_.find(order_number);
    if (it != orders_.end()) {
        // §3.3(3): cross-group collision on a combined feed. Count + warn
        // and replace the stale record (keeping both corrupts the levels).
        ++collisions;
        LOG_WARN("orders") << "order number collision: #" << order_number
                           << " already live (" << it->second.orderbook_id
                           << "), replacing with " << orderbook_id << " "
                           << side << " " << qty << "@" << price;
        remove_order(it->second);
    }
    Order order;
    order.order_number = order_number;
    order.orderbook_id = orderbook_id;
    order.group = group;
    order.side = side;
    order.price = price;
    order.remaining_qty = qty;
    orders_[order_number] = order;
    book(orderbook_id).add(side, price, qty);
}

void OrderBookStore::remove_order(const Order& order) {
    // Copy the fields we need before erasing (order may reference the
    // stored object).
    std::string oid = order.orderbook_id;
    char side = order.side;
    uint32_t price = order.price;
    uint32_t rem = order.remaining_qty;
    orders_.erase(order.order_number);
    book(oid).remove(side, price, rem);
}

bool OrderBookStore::execute(const ItchMsg& msg, Execution& execution) {
    std::unordered_map<uint64_t, Order>::iterator it =
        orders_.find(msg.order_number);
    if (it == orders_.end()) {
        ++orphan_executes;
        return false;
    }
    Order& order = it->second;
    uint32_t qty = msg.executed_qty;
    if (qty > order.remaining_qty) {
        // Should not happen on a clean feed; clamp so levels never go
        // negative, and make it loud.
        LOG_WARN("orders") << "execution of " << qty << " exceeds remaining "
                           << order.remaining_qty << " on #"
                           << order.order_number << "; clamping";
        ++clamped_executions;
        qty = order.remaining_qty;
    }
    order.remaining_qty -= qty;
    book(order.orderbook_id).remove(order.side, order.price, qty);
    execution.orderbook_id = order.orderbook_id;
    execution.group = order.group;
    execution.side = order.side;
    execution.price = order.price;
    execution.qty = qty;
    execution.match_number = msg.match_number;
    if (order.remaining_qty == 0) {
        orders_.erase(it);
    }
    executed_volume += qty;
    ++execution_count;
    return true;
}

void OrderBookStore::erase(const ItchMsg& msg) {
    std::unordered_map<uint64_t, Order>::iterator it =
        orders_.find(msg.order_number);
    if (it == orders_.end()) {
        ++orphan_deletes;
        return;
    }
    remove_order(it->second);
}

void OrderBookStore::replace(const ItchMsg& msg) {
    std::unordered_map<uint64_t, Order>::iterator it =
        orders_.find(msg.orig_order_number);
    if (it == orders_.end()) {
        // Without the original we know neither book nor side, so the new
        // order cannot be placed either (§3.3(2)).
        ++orphan_replaces;
        return;
    }
    // Copy inherited fields before removal invalidates the reference.
    std::string oid = it->second.orderbook_id;
    std::string group = it->second.group;
    char side = it->second.side;
    remove_order(it->second);
    insert(msg.new_order_number, oid, group, side, msg.price, msg.qty);
}

} // namespace jnx

// tape.h — trade tape: per-book cumulative stats. C++ port of
// jnxfeed/book/tape.py (per-book trade_count / volume / notional /
// last price+qty, plus feed totals). The prototype's rolling entry ring
// is not needed by the F2 dump; last_match_number is retained here (the
// prototype dumper tracks it from Market.apply's returned Executions —
// identical values by construction).
#ifndef JNX_MARKET_TAPE_H
#define JNX_MARKET_TAPE_H

#include <cstdint>
#include <map>
#include <string>

#include "market/orders.h"

namespace jnx {

struct BookStats {
    uint64_t trade_count;
    uint64_t volume;
    uint64_t notional; // sum(price * qty), raw price units
    int64_t last_price; // -1 = no trade yet
    int64_t last_qty;   // -1 = no trade yet
    uint64_t last_match_number;
    bool has_last;

    BookStats()
        : trade_count(0),
          volume(0),
          notional(0),
          last_price(-1),
          last_qty(-1),
          last_match_number(0),
          has_last(false) {}
};

class TradeTape {
public:
    TradeTape() : trade_count(0), total_volume(0) {}

    // Records one Execution at `timestamp_ns` (ns past midnight of the
    // session start day; kept for parity with the prototype signature —
    // the F2 state dump does not use it).
    void record(const Execution& execution, uint64_t timestamp_ns);

    const std::map<std::string, BookStats>& stats() const { return stats_; }

    uint64_t trade_count;  // total, feed-wide
    uint64_t total_volume; // total qty, feed-wide

private:
    std::map<std::string, BookStats> stats_; // orderbook_id -> stats
};

// Combine the T clock (seconds past midnight) with a message ns field.
inline uint64_t make_timestamp(uint64_t seconds, uint32_t ns) {
    return seconds * 1000000000ULL + static_cast<uint64_t>(ns);
}

} // namespace jnx

#endif // JNX_MARKET_TAPE_H

// tape.cpp — see tape.h.
#include "market/tape.h"

namespace jnx {

void TradeTape::record(const Execution& execution, uint64_t timestamp_ns) {
    (void)timestamp_ns; // ring entries (which carry it) arrive in a later phase
    ++trade_count;
    total_volume += execution.qty;

    BookStats& s = stats_[execution.orderbook_id];
    ++s.trade_count;
    s.volume += execution.qty;
    s.notional +=
        static_cast<uint64_t>(execution.price) * static_cast<uint64_t>(execution.qty);
    s.last_price = static_cast<int64_t>(execution.price);
    s.last_qty = static_cast<int64_t>(execution.qty);
    s.last_match_number = execution.match_number;
    s.has_last = true;
}

} // namespace jnx

// market.h — the market facade: C++ port of jnxfeed/book/market.py.
//
// Market::apply(msg) is the single entry point routing every decoded ITCH
// message to refdata / order store / tape, with the prototype's exact
// routing rules:
//   T            -> session clock only
//   G            -> end_of_snapshot_seq only
//   A with order_number==0 (ref-price) -> refdata only
//   A/F/D/U      -> order store
//   E            -> order store; a matched execution is recorded on the
//                   tape at make_timestamp(seconds, msg.ns)
//   R/L/H/Y/S    -> refdata
//   anything else -> unknown_count (never fatal)
//
// ApplyResult additionally reports what changed — exactly what the record
// builder (F3/F5) needs to assemble one UPDATE per message.
#ifndef JNX_MARKET_MARKET_H
#define JNX_MARKET_MARKET_H

#include <cstdint>
#include <map>
#include <string>

#include "itch/itch.h"
#include "market/orders.h"
#include "market/refdata.h"
#include "market/tape.h"

namespace jnx {

// Which state sections a message changed (bitmask).
enum Section {
    SEC_STATIC = 1, // T1: R/L
    SEC_STATE = 2,  // T2: H/Y/S/ref-price A
    SEC_BOOK = 4,   // T3/T4: A/F/E/D/U
    SEC_TRADE = 8   // T5: matched E
};

struct ApplyResult {
    bool applied;    // type recognized and consumed
    char trigger;    // the ITCH type char ('\0' if unknown)
    uint8_t sections; // Section bitmask (0 for T/G/orphans/unknown)

    // Affected book, when the message resolves to one ("" otherwise —
    // T/G/S(system-wide)/orphan E/D/U).
    std::string ticker;
    std::string group;

    // Order-level delta for A/F/E/D/U that touched the store.
    bool has_delta;
    char delta_op; // A/F/E/D/U
    uint64_t order_number;      // the affected order (U: the NEW number)
    uint64_t orig_order_number; // U only, else 0
    char side;
    uint32_t price; // E: passive stored price; A/F/U: message price
    uint32_t qty;   // E: clamped executed qty; A/F/U: message qty
    char order_type; // 'Q' for F DLP orders, else ' '

    // Trade info for a matched E.
    bool has_trade;
    Execution trade;

    ApplyResult()
        : applied(false),
          trigger('\0'),
          sections(0),
          has_delta(false),
          delta_op('\0'),
          order_number(0),
          orig_order_number(0),
          side('\0'),
          price(0),
          qty(0),
          order_type(' '),
          has_trade(false) {}
};

class Market {
public:
    Market() : seconds(0), end_of_snapshot_seq(0), has_end_of_snapshot(false),
               unknown_count(0) {}

    ApplyResult apply(const ItchMsg& msg);

    RefData refdata;
    OrderBookStore books;
    TradeTape tape;

    // Last T value: seconds past midnight of the session start day.
    uint64_t seconds;
    // Sequence carried by a G End of Snapshot (GLIMPSE only).
    uint64_t end_of_snapshot_seq;
    bool has_end_of_snapshot;

    // Applied-message counters by ITCH type char (sorted by char).
    std::map<char, uint64_t> message_counts;
    uint64_t unknown_count;
};

} // namespace jnx

#endif // JNX_MARKET_MARKET_H

// market.cpp — see market.h. Routing mirrors jnxfeed/book/market.py; the
// extra ApplyResult detail (ticker resolution for D/U via a store peek)
// changes no state and exists only for record building.
#include "market/market.h"

namespace jnx {

namespace {

bool known_type(char t) {
    switch (t) {
        case 'T': case 'S': case 'L': case 'R': case 'H': case 'Y':
        case 'A': case 'F': case 'E': case 'D': case 'U': case 'G':
            return true;
        default:
            return false;
    }
}

} // namespace

ApplyResult Market::apply(const ItchMsg& msg) {
    ApplyResult res;
    if (!known_type(msg.type)) {
        ++unknown_count;
        return res;
    }
    ++message_counts[msg.type];
    res.applied = true;
    res.trigger = msg.type;

    Execution execution;
    switch (msg.type) {
        case 'T':
            seconds = msg.seconds;
            return res;
        case 'G':
            end_of_snapshot_seq = msg.sequence_number;
            has_end_of_snapshot = true;
            return res;
        case 'A':
        case 'F':
            if (msg.type == 'A' && msg.order_number == 0) {
                // Reference-price pseudo-order: refdata only (§3.3(1)).
                refdata.apply(msg);
                res.sections = SEC_STATE;
                res.ticker = msg.orderbook_id;
                res.group = msg.group;
                return res;
            }
            books.apply(msg, execution);
            res.sections = SEC_BOOK;
            res.ticker = msg.orderbook_id;
            res.group = msg.group;
            res.has_delta = true;
            res.delta_op = msg.type;
            res.order_number = msg.order_number;
            res.side = msg.side;
            res.price = msg.price;
            res.qty = msg.qty;
            res.order_type = (msg.type == 'F') ? msg.order_type : ' ';
            return res;
        case 'E':
            if (books.apply(msg, execution)) {
                tape.record(execution, make_timestamp(seconds, msg.ns));
                res.sections = SEC_BOOK | SEC_TRADE;
                res.ticker = execution.orderbook_id;
                res.group = execution.group;
                res.has_delta = true;
                res.delta_op = 'E';
                res.order_number = msg.order_number;
                res.side = execution.side;
                res.price = execution.price; // passive stored price
                res.qty = execution.qty;     // clamped executed qty
                res.has_trade = true;
                res.trade = execution;
            }
            return res; // orphan E: applied, but nothing changed
        case 'D': {
            // Peek before applying so the delta can name the affected book
            // (the store mutation itself is untouched prototype logic).
            std::unordered_map<uint64_t, Order>::const_iterator it =
                books.orders().find(msg.order_number);
            if (it != books.orders().end()) {
                res.sections = SEC_BOOK;
                res.ticker = it->second.orderbook_id;
                res.group = it->second.group;
                res.has_delta = true;
                res.delta_op = 'D';
                res.order_number = msg.order_number;
                res.side = it->second.side;
                res.price = it->second.price;
                res.qty = it->second.remaining_qty;
            }
            books.apply(msg, execution);
            return res;
        }
        case 'U': {
            std::unordered_map<uint64_t, Order>::const_iterator it =
                books.orders().find(msg.orig_order_number);
            if (it != books.orders().end()) {
                res.sections = SEC_BOOK;
                res.ticker = it->second.orderbook_id;
                res.group = it->second.group;
                res.has_delta = true;
                res.delta_op = 'U';
                res.order_number = msg.new_order_number;
                res.orig_order_number = msg.orig_order_number;
                res.side = it->second.side; // inherited from the original
                res.price = msg.price;
                res.qty = msg.qty;
            }
            books.apply(msg, execution);
            return res;
        }
        case 'R':
        case 'L':
            refdata.apply(msg);
            res.sections = SEC_STATIC;
            if (msg.type == 'R') {
                res.ticker = msg.orderbook_id;
                res.group = msg.group;
            }
            return res;
        case 'H':
        case 'Y':
            refdata.apply(msg);
            res.sections = SEC_STATE;
            res.ticker = msg.orderbook_id;
            res.group = msg.group;
            return res;
        case 'S':
            refdata.apply(msg);
            res.sections = SEC_STATE;
            res.group = msg.group; // "" = system-wide
            return res;
        default:
            return res; // unreachable (known_type gate)
    }
}

} // namespace jnx

// book_dump — replay a .itch file through the C++ Market and write the
// canonical state dump. MUST stay byte-identical to
// tools/proto_state_dump.py (the format contract is documented there —
// keep the two in sync).
//
// Usage: book_dump <file.itch> <outdir>
#include <sys/stat.h>

#include <cstdio>
#include <cstring>
#include <map>
#include <string>
#include <utility>
#include <vector>

#include "itch/itch.h"
#include "market/market.h"

namespace {

// None-style optional int: -1 renders as empty.
std::string opt64(int64_t v) {
    if (v < 0) {
        return std::string();
    }
    char buf[24];
    std::snprintf(buf, sizeof(buf), "%lld", static_cast<long long>(v));
    return std::string(buf);
}

std::string u64s(uint64_t v) {
    char buf[24];
    std::snprintf(buf, sizeof(buf), "%llu", static_cast<unsigned long long>(v));
    return std::string(buf);
}

std::string group_of(const jnx::Market& market, const std::string& oid) {
    std::map<std::string, jnx::Instrument>::const_iterator it =
        market.refdata.instruments().find(oid);
    if (it == market.refdata.instruments().end()) {
        return std::string();
    }
    return it->second.group;
}

} // namespace

int main(int argc, char** argv) {
    if (argc != 3) {
        std::fprintf(stderr, "usage: book_dump <file.itch> <outdir>\n");
        return 2;
    }
    std::FILE* in = std::fopen(argv[1], "rb");
    if (in == NULL) {
        std::fprintf(stderr, "book_dump: cannot open %s\n", argv[1]);
        return 2;
    }

    jnx::Market market;
    // orderbook_id -> match number of its last execution (tracked from
    // apply results, exactly like the Python dumper does).
    std::map<std::string, uint64_t> last_match;

    unsigned char lenbuf[2];
    unsigned char msgbuf[65536];
    for (;;) {
        size_t got = std::fread(lenbuf, 1, 2, in);
        if (got == 0) {
            break;
        }
        if (got != 2) {
            std::fprintf(stderr, "book_dump: truncated length prefix\n");
            std::fclose(in);
            return 1;
        }
        size_t mlen = (static_cast<size_t>(lenbuf[0]) << 8) |
                      static_cast<size_t>(lenbuf[1]);
        if (mlen == 0 || std::fread(msgbuf, 1, mlen, in) != mlen) {
            std::fprintf(stderr, "book_dump: truncated message body\n");
            std::fclose(in);
            return 1;
        }
        jnx::ItchMsg msg;
        const char* err = NULL;
        if (!jnx::decode(msgbuf, mlen, msg, &err)) {
            std::fprintf(stderr, "book_dump: decode error: %s\n",
                         err ? err : "?");
            std::fclose(in);
            return 1;
        }
        jnx::ApplyResult res = market.apply(msg);
        if (res.has_trade) {
            last_match[res.trade.orderbook_id] = res.trade.match_number;
        }
    }
    std::fclose(in);

    std::string outdir(argv[2]);
    ::mkdir(outdir.c_str(), 0777); // best-effort, single level like makedirs

    // --- refdata.csv ------------------------------------------------------
    {
        std::string path = outdir + "/refdata.csv";
        std::FILE* f = std::fopen(path.c_str(), "w");
        if (f == NULL) {
            std::fprintf(stderr, "book_dump: cannot write %s\n", path.c_str());
            return 1;
        }
        std::fputs(
            "orderbook_id,isin,group,round_lot,tick_table_id,price_decimals,"
            "upper_limit,lower_limit,trading_state,short_sell_state,"
            "reference_price,directory_missing\n",
            f);
        const std::map<std::string, jnx::Instrument>& insts =
            market.refdata.instruments();
        for (std::map<std::string, jnx::Instrument>::const_iterator it =
                 insts.begin();
             it != insts.end(); ++it) {
            const jnx::Instrument& i = it->second;
            std::fprintf(f, "%s,%s,%s,%s,%s,%s,%s,%s,%c,%c,%s,%d\n",
                         i.orderbook_id.c_str(), i.isin.c_str(),
                         i.group.c_str(), opt64(i.round_lot).c_str(),
                         opt64(i.tick_table_id).c_str(),
                         opt64(i.price_decimals).c_str(),
                         opt64(i.upper_limit).c_str(),
                         opt64(i.lower_limit).c_str(), i.trading_state,
                         i.short_sell_state,
                         opt64(i.reference_price).c_str(),
                         i.directory_missing ? 1 : 0);
        }
        std::fclose(f);
    }

    // Per-(book, side, price) live order counts and per-(book, side)
    // totals, derived from the order store (matches the Python dumper).
    typedef std::pair<std::string, char> SideKey;
    std::map<std::pair<SideKey, uint32_t>, uint64_t> level_orders;
    std::map<SideKey, uint64_t> side_orders;
    {
        const std::unordered_map<uint64_t, jnx::Order>& orders =
            market.books.orders();
        for (std::unordered_map<uint64_t, jnx::Order>::const_iterator it =
                 orders.begin();
             it != orders.end(); ++it) {
            const jnx::Order& o = it->second;
            SideKey sk(o.orderbook_id, o.side);
            ++level_orders[std::make_pair(sk, o.price)];
            ++side_orders[sk];
        }
    }

    // --- books.csv --------------------------------------------------------
    {
        std::string path = outdir + "/books.csv";
        std::FILE* f = std::fopen(path.c_str(), "w");
        if (f == NULL) return 1;
        std::fputs("orderbook_id,group,kind,side,price,qty,order_count\n", f);
        const std::map<std::string, jnx::Book>& books = market.books.books();
        for (std::map<std::string, jnx::Book>::const_iterator bit =
                 books.begin();
             bit != books.end(); ++bit) {
            const std::string& oid = bit->first;
            const jnx::Book& book = bit->second;
            std::string grp = group_of(market, oid);
            // Bid levels best-first (descending price).
            const jnx::SideLevels::LevelMap& bids = book.bids().ascending();
            for (jnx::SideLevels::LevelMap::const_reverse_iterator it =
                     bids.rbegin();
                 it != bids.rend(); ++it) {
                uint64_t oc = level_orders[std::make_pair(SideKey(oid, 'B'),
                                                          it->first)];
                std::fprintf(f, "%s,%s,level,B,%u,%s,%s\n", oid.c_str(),
                             grp.c_str(), it->first, u64s(it->second).c_str(),
                             u64s(oc).c_str());
            }
            // Ask levels best-first (ascending price).
            const jnx::SideLevels::LevelMap& asks = book.asks().ascending();
            for (jnx::SideLevels::LevelMap::const_iterator it = asks.begin();
                 it != asks.end(); ++it) {
                uint64_t oc = level_orders[std::make_pair(SideKey(oid, 'S'),
                                                          it->first)];
                std::fprintf(f, "%s,%s,level,S,%u,%s,%s\n", oid.c_str(),
                             grp.c_str(), it->first, u64s(it->second).c_str(),
                             u64s(oc).c_str());
            }
            std::fprintf(f, "%s,%s,total,B,,%s,%s\n", oid.c_str(), grp.c_str(),
                         u64s(book.bids().total_qty()).c_str(),
                         u64s(side_orders[SideKey(oid, 'B')]).c_str());
            std::fprintf(f, "%s,%s,total,S,,%s,%s\n", oid.c_str(), grp.c_str(),
                         u64s(book.asks().total_qty()).c_str(),
                         u64s(side_orders[SideKey(oid, 'S')]).c_str());
        }
        std::fclose(f);
    }

    // --- orders.csv -------------------------------------------------------
    {
        std::string path = outdir + "/orders.csv";
        std::FILE* f = std::fopen(path.c_str(), "w");
        if (f == NULL) return 1;
        std::fputs("order_number,orderbook_id,group,side,price,"
                   "remaining_qty\n",
                   f);
        // Sort by order number explicitly (store is unordered).
        std::map<uint64_t, const jnx::Order*> sorted;
        const std::unordered_map<uint64_t, jnx::Order>& orders =
            market.books.orders();
        for (std::unordered_map<uint64_t, jnx::Order>::const_iterator it =
                 orders.begin();
             it != orders.end(); ++it) {
            sorted[it->first] = &it->second;
        }
        for (std::map<uint64_t, const jnx::Order*>::const_iterator it =
                 sorted.begin();
             it != sorted.end(); ++it) {
            const jnx::Order& o = *it->second;
            std::fprintf(f, "%s,%s,%s,%c,%u,%u\n",
                         u64s(o.order_number).c_str(), o.orderbook_id.c_str(),
                         o.group.c_str(), o.side, o.price, o.remaining_qty);
        }
        std::fclose(f);
    }

    // --- trades.csv -------------------------------------------------------
    {
        std::string path = outdir + "/trades.csv";
        std::FILE* f = std::fopen(path.c_str(), "w");
        if (f == NULL) return 1;
        std::fputs("orderbook_id,group,trade_count,cum_qty,cum_turnover,"
                   "last_price,last_qty,last_match_number\n",
                   f);
        const std::map<std::string, jnx::BookStats>& stats =
            market.tape.stats();
        for (std::map<std::string, jnx::BookStats>::const_iterator it =
                 stats.begin();
             it != stats.end(); ++it) {
            const jnx::BookStats& s = it->second;
            std::map<std::string, uint64_t>::const_iterator lm =
                last_match.find(it->first);
            std::fprintf(f, "%s,%s,%s,%s,%s,%s,%s,%s\n", it->first.c_str(),
                         group_of(market, it->first).c_str(),
                         u64s(s.trade_count).c_str(), u64s(s.volume).c_str(),
                         u64s(s.notional).c_str(), opt64(s.last_price).c_str(),
                         opt64(s.last_qty).c_str(),
                         lm == last_match.end() ? ""
                                                : u64s(lm->second).c_str());
        }
        std::fclose(f);
    }

    // --- stats.csv --------------------------------------------------------
    {
        std::string path = outdir + "/stats.csv";
        std::FILE* f = std::fopen(path.c_str(), "w");
        if (f == NULL) return 1;
        std::fputs("key,value\n", f);
        uint64_t applied = 0;
        for (std::map<char, uint64_t>::const_iterator it =
                 market.message_counts.begin();
             it != market.message_counts.end(); ++it) {
            applied += it->second;
        }
        uint64_t auto_created = 0;
        const std::map<std::string, jnx::Instrument>& insts =
            market.refdata.instruments();
        for (std::map<std::string, jnx::Instrument>::const_iterator it =
                 insts.begin();
             it != insts.end(); ++it) {
            if (it->second.directory_missing) {
                ++auto_created;
            }
        }
        std::fprintf(f, "messages_applied,%s\n", u64s(applied).c_str());
        std::fprintf(f, "unknown,%s\n", u64s(market.unknown_count).c_str());
        for (std::map<char, uint64_t>::const_iterator it =
                 market.message_counts.begin();
             it != market.message_counts.end(); ++it) {
            std::fprintf(f, "msg_%c,%s\n", it->first,
                         u64s(it->second).c_str());
        }
        std::fprintf(f, "instruments,%zu\n", insts.size());
        std::fprintf(f, "auto_created_books,%s\n", u64s(auto_created).c_str());
        std::fprintf(f, "books,%zu\n", market.books.books().size());
        std::fprintf(f, "live_orders,%zu\n", market.books.orders().size());
        std::fprintf(f, "collisions,%s\n",
                     u64s(market.books.collisions).c_str());
        std::fprintf(f, "orphan_executes,%s\n",
                     u64s(market.books.orphan_executes).c_str());
        std::fprintf(f, "orphan_deletes,%s\n",
                     u64s(market.books.orphan_deletes).c_str());
        std::fprintf(f, "orphan_replaces,%s\n",
                     u64s(market.books.orphan_replaces).c_str());
        std::fprintf(f, "ref_price_ignored,%s\n",
                     u64s(market.books.ref_price_ignored).c_str());
        std::fprintf(f, "execution_count,%s\n",
                     u64s(market.books.execution_count).c_str());
        std::fprintf(f, "executed_volume,%s\n",
                     u64s(market.books.executed_volume).c_str());
        std::fprintf(f, "trade_count,%s\n",
                     u64s(market.tape.trade_count).c_str());
        std::fprintf(f, "total_volume,%s\n",
                     u64s(market.tape.total_volume).c_str());
        std::fclose(f);
    }

    return 0;
}

// test_market.cpp — unit tests for every JNX_PLAN.md §3.3 gotcha, plus a
// randomized store-vs-levels invariant check.
#include "market/market.h"

#include <cstdio>
#include <cstring>
#include <random>
#include <string>
#include <vector>

#include "common/minitest.h"

namespace {

jnx::ItchMsg make_add(uint64_t number, const char* oid, const char* group,
                      char side, uint32_t qty, uint32_t price,
                      bool with_attrs = false, char order_type = ' ') {
    jnx::ItchMsg m;
    m.type = with_attrs ? 'F' : 'A';
    m.ns = 1;
    m.order_number = number;
    m.side = side;
    m.qty = qty;
    std::snprintf(m.orderbook_id, sizeof(m.orderbook_id), "%s", oid);
    std::snprintf(m.group, sizeof(m.group), "%s", group);
    m.price = price;
    m.order_type = order_type;
    return m;
}

jnx::ItchMsg make_exec(uint64_t number, uint32_t qty, uint64_t match) {
    jnx::ItchMsg m;
    m.type = 'E';
    m.ns = 2;
    m.order_number = number;
    m.executed_qty = qty;
    m.match_number = match;
    return m;
}

jnx::ItchMsg make_delete(uint64_t number) {
    jnx::ItchMsg m;
    m.type = 'D';
    m.ns = 3;
    m.order_number = number;
    return m;
}

jnx::ItchMsg make_replace(uint64_t orig, uint64_t newnum, uint32_t qty,
                          uint32_t price) {
    jnx::ItchMsg m;
    m.type = 'U';
    m.ns = 4;
    m.orig_order_number = orig;
    m.new_order_number = newnum;
    m.qty = qty;
    m.price = price;
    return m;
}

// Invariant: for every book+side, the levels' total qty equals the sum of
// live orders' remaining qty, and level count/qty per price match.
bool store_levels_consistent(const jnx::Market& market) {
    typedef std::pair<std::string, char> SideKey;
    std::map<std::pair<SideKey, uint32_t>, uint64_t> want;
    std::map<SideKey, uint64_t> want_total;
    const std::unordered_map<uint64_t, jnx::Order>& orders =
        market.books.orders();
    for (std::unordered_map<uint64_t, jnx::Order>::const_iterator it =
             orders.begin();
         it != orders.end(); ++it) {
        const jnx::Order& o = it->second;
        want[std::make_pair(SideKey(o.orderbook_id, o.side), o.price)] +=
            o.remaining_qty;
        want_total[SideKey(o.orderbook_id, o.side)] += o.remaining_qty;
    }
    const std::map<std::string, jnx::Book>& books = market.books.books();
    for (std::map<std::string, jnx::Book>::const_iterator bit = books.begin();
         bit != books.end(); ++bit) {
        const char sides[2] = {'B', 'S'};
        for (int s = 0; s < 2; ++s) {
            const jnx::SideLevels& sl =
                sides[s] == 'B' ? bit->second.bids() : bit->second.asks();
            uint64_t total = 0;
            for (jnx::SideLevels::LevelMap::const_iterator it =
                     sl.ascending().begin();
                 it != sl.ascending().end(); ++it) {
                if (it->second == 0) return false; // empty level retained
                std::map<std::pair<SideKey, uint32_t>, uint64_t>::iterator w =
                    want.find(std::make_pair(SideKey(bit->first, sides[s]),
                                             it->first));
                if (w == want.end() || w->second != it->second) return false;
                want.erase(w);
                total += it->second;
            }
            std::map<SideKey, uint64_t>::iterator wt =
                want_total.find(SideKey(bit->first, sides[s]));
            uint64_t want_t = wt == want_total.end() ? 0 : wt->second;
            if (total != want_t) return false;
        }
    }
    return want.empty(); // no store order without a matching level
}

} // namespace

TEST(ref_price_a_never_enters_book) {
    jnx::Market market;
    jnx::ItchMsg ref = make_add(0, "8306", "DAY", 'B', 0, 15000);
    jnx::ApplyResult r = market.apply(ref);
    CHECK(r.applied);
    CHECK_EQ(static_cast<int>(r.sections), static_cast<int>(jnx::SEC_STATE));
    CHECK(!r.has_delta);
    CHECK_EQ(market.books.books().size(), static_cast<size_t>(0));
    CHECK_EQ(market.books.orders().size(), static_cast<size_t>(0));
    const jnx::Instrument& inst = market.refdata.get("8306");
    CHECK_EQ(inst.reference_price, static_cast<int64_t>(15000));
    CHECK_EQ(inst.group, std::string("DAY"));

    // NO_PRICE sentinel is stored verbatim.
    jnx::ItchMsg ref2 = make_add(0, "8306", "DAY", 'B', 0, jnx::NO_PRICE);
    market.apply(ref2);
    CHECK_EQ(market.refdata.get("8306").reference_price,
             static_cast<int64_t>(jnx::NO_PRICE));
    CHECK_EQ(market.books.ref_price_ignored, static_cast<uint64_t>(0));
}

TEST(execute_passive_price_multifill_and_removal_at_zero) {
    jnx::Market market;
    market.apply(make_add(42, "8306", "DAY", 'S', 300, 15000));
    // Aggressor price is unknown to the feed; trade price must be the
    // STORED order's price. Three fills, one trade each.
    jnx::ApplyResult r1 = market.apply(make_exec(42, 100, 1001));
    CHECK(r1.has_trade);
    CHECK_EQ(r1.trade.price, static_cast<uint32_t>(15000));
    CHECK_EQ(r1.trade.qty, static_cast<uint32_t>(100));
    CHECK_EQ(std::string(1, r1.trade.side), std::string("S"));
    CHECK_EQ(r1.trade.match_number, static_cast<uint64_t>(1001));
    CHECK_EQ(market.books.orders().at(42).remaining_qty,
             static_cast<uint32_t>(200));

    jnx::ApplyResult r2 = market.apply(make_exec(42, 150, 1002));
    CHECK(r2.has_trade);
    CHECK_EQ(market.books.orders().at(42).remaining_qty,
             static_cast<uint32_t>(50));

    jnx::ApplyResult r3 = market.apply(make_exec(42, 50, 1003));
    CHECK(r3.has_trade);
    // Removed at exactly zero.
    CHECK(market.books.orders().find(42) == market.books.orders().end());
    CHECK_EQ(market.books.execution_count, static_cast<uint64_t>(3));
    CHECK_EQ(market.books.executed_volume, static_cast<uint64_t>(300));
    CHECK_EQ(market.tape.trade_count, static_cast<uint64_t>(3));
    // Level fully consumed.
    const jnx::Book& book = market.books.books().at("8306");
    CHECK_EQ(book.asks().size(), static_cast<size_t>(0));
}

TEST(over_execution_clamps_to_zero) {
    jnx::Market market;
    market.apply(make_add(7, "8306", "DAY", 'B', 100, 20000));
    jnx::ApplyResult r = market.apply(make_exec(7, 500, 2001));
    CHECK(r.has_trade);
    CHECK_EQ(r.trade.qty, static_cast<uint32_t>(100)); // clamped
    CHECK(market.books.orders().find(7) == market.books.orders().end());
    CHECK_EQ(market.books.clamped_executions, static_cast<uint64_t>(1));
    CHECK_EQ(market.books.executed_volume, static_cast<uint64_t>(100));
    CHECK(store_levels_consistent(market));
}

TEST(orphan_execute_delete_replace_counted_never_fatal) {
    jnx::Market market;
    jnx::ApplyResult re = market.apply(make_exec(999, 10, 1));
    CHECK(re.applied);
    CHECK(!re.has_trade);
    CHECK(!re.has_delta);
    CHECK_EQ(re.ticker, std::string(""));
    market.apply(make_delete(998));
    market.apply(make_replace(997, 1997, 100, 5000));
    CHECK_EQ(market.books.orphan_executes, static_cast<uint64_t>(1));
    CHECK_EQ(market.books.orphan_deletes, static_cast<uint64_t>(1));
    CHECK_EQ(market.books.orphan_replaces, static_cast<uint64_t>(1));
    // Orphan U inserts NOTHING.
    CHECK_EQ(market.books.orders().size(), static_cast<size_t>(0));
    CHECK_EQ(market.tape.trade_count, static_cast<uint64_t>(0));
}

TEST(replace_inherits_from_original) {
    jnx::Market market;
    market.apply(make_add(10, "7203", "NGHT", 'S', 400, 26000));
    jnx::ApplyResult r = market.apply(make_replace(10, 11, 250, 26500));
    CHECK(r.has_delta);
    CHECK_EQ(std::string(1, r.delta_op), std::string("U"));
    CHECK_EQ(r.order_number, static_cast<uint64_t>(11));
    CHECK_EQ(r.orig_order_number, static_cast<uint64_t>(10));
    CHECK_EQ(r.ticker, std::string("7203"));
    CHECK(market.books.orders().find(10) == market.books.orders().end());
    const jnx::Order& o = market.books.orders().at(11);
    CHECK_EQ(o.orderbook_id, std::string("7203")); // inherited
    CHECK_EQ(o.group, std::string("NGHT"));        // inherited
    CHECK_EQ(std::string(1, o.side), std::string("S")); // inherited
    CHECK_EQ(o.price, static_cast<uint32_t>(26500)); // from message
    CHECK_EQ(o.remaining_qty, static_cast<uint32_t>(250)); // from message
    CHECK(store_levels_consistent(market));
}

TEST(collision_replaces_stale_order) {
    jnx::Market market;
    market.apply(make_add(5, "8306", "DAY", 'B', 100, 15000));
    market.apply(make_add(5, "7203", "DAY", 'S', 200, 26000));
    CHECK_EQ(market.books.collisions, static_cast<uint64_t>(1));
    CHECK_EQ(market.books.orders().size(), static_cast<size_t>(1));
    const jnx::Order& o = market.books.orders().at(5);
    CHECK_EQ(o.orderbook_id, std::string("7203"));
    // The stale order's level must be gone.
    CHECK_EQ(market.books.books().at("8306").bids().size(),
             static_cast<size_t>(0));
    CHECK(store_levels_consistent(market));
}

TEST(auto_create_and_absence_defaults) {
    jnx::Market market;
    // First reference via H: auto-created, directory_missing until R.
    jnx::ItchMsg h;
    h.type = 'H';
    h.ns = 5;
    std::snprintf(h.orderbook_id, sizeof(h.orderbook_id), "9984");
    std::snprintf(h.group, sizeof(h.group), "DAY");
    h.state = 'T';
    market.apply(h);
    const jnx::Instrument& inst = market.refdata.get("9984");
    CHECK(inst.directory_missing);
    CHECK_EQ(std::string(1, inst.trading_state), std::string("T"));
    // Absence defaults on a fresh instrument (§3.3(4)).
    const jnx::Instrument& fresh = market.refdata.get("0000");
    CHECK_EQ(std::string(1, fresh.trading_state), std::string("V"));
    CHECK_EQ(std::string(1, fresh.short_sell_state), std::string("0"));
    CHECK(fresh.directory_missing);

    // R clears directory_missing.
    jnx::ItchMsg r;
    r.type = 'R';
    r.ns = 6;
    std::snprintf(r.orderbook_id, sizeof(r.orderbook_id), "9984");
    std::snprintf(r.isin, sizeof(r.isin), "JP0000000000");
    std::snprintf(r.group, sizeof(r.group), "DAY");
    r.round_lot = 100;
    r.tick_table_id = 1;
    r.price_decimals = 1;
    r.upper_limit = 99999;
    r.lower_limit = 1;
    market.apply(r);
    CHECK(!market.refdata.get("9984").directory_missing);
    CHECK_EQ(market.refdata.get("9984").isin, std::string("JP0000000000"));
}

TEST(tick_table_rows_sorted_and_replace) {
    jnx::Market market;
    jnx::ItchMsg l;
    l.type = 'L';
    l.ns = 1;
    l.tick_table_id = 3;
    l.tick_size = 5;
    l.price_start = 10000;
    market.apply(l);
    l.tick_size = 1;
    l.price_start = 0;
    market.apply(l);
    l.tick_size = 10; // duplicate start replaces
    l.price_start = 10000;
    market.apply(l);
    const jnx::TickTable& tt = market.refdata.tick_tables().at(3);
    CHECK_EQ(tt.rows().size(), static_cast<size_t>(2));
    uint32_t ts = 0;
    CHECK(tt.tick_size(9999, ts));
    CHECK_EQ(ts, static_cast<uint32_t>(1));
    CHECK(tt.tick_size(10000, ts));
    CHECK_EQ(ts, static_cast<uint32_t>(10));
}

TEST(randomized_store_levels_invariant) {
    jnx::Market market;
    std::mt19937 rng(20260711u);
    std::vector<uint64_t> live;
    const char* oids[4] = {"8306", "7203", "1570", "1H2J"};
    uint64_t next_number = 1;
    for (int i = 0; i < 5000; ++i) {
        unsigned pick = rng() % 100;
        if (pick < 45 || live.empty()) {
            // Add.
            uint64_t num = next_number++;
            const char* oid = oids[rng() % 4];
            char side = (rng() % 2 == 0) ? 'B' : 'S';
            uint32_t qty = 1 + rng() % 1000;
            uint32_t price = 100 * (1 + rng() % 50);
            market.apply(make_add(num, oid, "DAY", side, qty, price,
                                  rng() % 5 == 0, 'Q'));
            live.push_back(num);
        } else {
            size_t idx = rng() % live.size();
            uint64_t num = live[idx];
            uint32_t rem = market.books.orders().at(num).remaining_qty;
            if (pick < 70) {
                // Execute (sometimes over-executing to exercise the clamp).
                uint32_t q = 1 + rng() % (rem + rem / 4 + 1);
                market.apply(make_exec(num, q, 100000 + i));
                if (market.books.orders().find(num) ==
                    market.books.orders().end()) {
                    live.erase(live.begin() + idx);
                }
            } else if (pick < 85) {
                market.apply(make_delete(num));
                live.erase(live.begin() + idx);
            } else {
                uint64_t newnum = next_number++;
                market.apply(make_replace(num, newnum, 1 + rng() % 1000,
                                          100 * (1 + rng() % 50)));
                live[idx] = newnum;
            }
        }
        // Sampled per-message check (cheap subset), full check at the end.
        if (i % 250 == 0) {
            CHECK(store_levels_consistent(market));
        }
    }
    // A few orphans on top (unknown numbers) — never fatal.
    market.apply(make_exec(999999999, 1, 1));
    market.apply(make_delete(999999998));
    market.apply(make_replace(999999997, 999999996, 10, 100));
    CHECK(store_levels_consistent(market));
    CHECK_EQ(market.books.orders().size(), live.size());
    CHECK_EQ(market.books.orphan_executes, static_cast<uint64_t>(1));
    CHECK_EQ(market.books.orphan_deletes, static_cast<uint64_t>(1));
    CHECK_EQ(market.books.orphan_replaces, static_cast<uint64_t>(1));
}

