1	// record.h — JNX record codec: the single wire format for the FH->DB UDS
2	// stream, the DB->FH recovery stream, and the UDP multicast feed.
3	//
4	// Byte layout is FROZEN by docs/wire_spec.md (version 1) — both this codec
5	// and jnxweb/records.py implement that document exactly. All integers are
6	// big-endian on the wire; all byte access goes through cpp/common/endian.h
7	// (never struct casts). Alpha fields are space-padded on encode, stripped
8	// on decode. Every unused/padding byte is zero-filled on encode.
9	#ifndef JNX_WIRE_RECORD_H
10	#define JNX_WIRE_RECORD_H
11	
12	#include <cstddef>
13	#include <cstdint>
14	#include <vector>
15	
16	namespace jnx {
17	
18	// --- header ---------------------------------------------------------------
19	
20	const uint16_t RECORD_MAGIC = 0x4A58;  // "JX"
21	const uint8_t RECORD_VERSION = 1;
22	const size_t RECORD_HEADER_SIZE = 8;
23	
24	// Record kinds (header `kind` byte).
25	const char KIND_UPDATE = 'U';
26	const char KIND_ORDER = 'O';
27	const char KIND_TICK = 'K';
28	const char KIND_SYNC_BEGIN = 'B';
29	const char KIND_SYNC_END = 'E';
30	const char KIND_GET_STATE = 'G';
31	const char KIND_HELLO = 'H';
32	const char KIND_RESET = 'R';
33	
34	// Fixed body sizes per kind (docs/wire_spec.md).
35	const size_t UPDATE_BODY_SIZE = 425;
36	const size_t ORDER_BODY_SIZE = 26;
37	const size_t TICK_BODY_SIZE = 12;
38	const size_t SYNC_END_BODY_SIZE = 26;
39	const size_t HELLO_BODY_SIZE = 16;
40	// SYNC_BEGIN / GET_STATE / RESET have empty bodies.
41	
42	const size_t UPDATE_WIRE_SIZE = RECORD_HEADER_SIZE + UPDATE_BODY_SIZE;  // 433
43	const size_t ORDER_WIRE_SIZE = RECORD_HEADER_SIZE + ORDER_BODY_SIZE;    // 34
44	const size_t TICK_WIRE_SIZE = RECORD_HEADER_SIZE + TICK_BODY_SIZE;      // 20
45	const size_t SYNC_END_WIRE_SIZE = RECORD_HEADER_SIZE + SYNC_END_BODY_SIZE; // 34
46	const size_t HELLO_WIRE_SIZE = RECORD_HEADER_SIZE + HELLO_BODY_SIZE;    // 24
47	const size_t CONTROL_WIRE_SIZE = RECORD_HEADER_SIZE;  // B / G / R      // 8
48	
49	// Largest possible record — handy for caller-side buffers.
50	const size_t MAX_RECORD_WIRE_SIZE = UPDATE_WIRE_SIZE;
51	
52	// Fixed body size for a kind; -1 for unknown kinds.
53	int record_body_len(char kind);
54	
55	// --- UPDATE ----------------------------------------------------------------
56	
57	const int BOOK_DEPTH = 10;
58	
59	struct BookLevel {
60	    uint32_t price;
61	    uint32_t qty;
62	    uint32_t order_count;
63	
64	    BookLevel() : price(0), qty(0), order_count(0) {}
65	};
66	
67	// Flags byte (static section) bit assignments — docs/wire_spec.md.
68	const uint8_t FLAG_DIRECTORY_SEEN = 0x01;
69	const uint8_t FLAG_ORDER_COLLISION_SEEN = 0x02;
70	
71	// Full merged per-(ticker,group) row + order delta. Host-order fields;
72	// char[] fields are NUL-terminated stripped strings (one extra byte).
73	// Single-char tag fields use '\0' for "not applicable / no value".
74	struct UpdateRecord {
75	    // envelope
76	    uint64_t epoch;
77	    uint64_t pub_seq;
78	    char session[11];  // <= 10 chars
79	    uint64_t exch_seq;
80	    uint64_t exch_ns;
81	    char trigger;      // ITCH type char, or '#' for sync-dump rows
82	    char ticker[5];    // 4-byte alpha (SICC — a string, NOT a number)
83	    char group[5];     // 4-byte alpha
84	
85	    // static section (T1)
86	    char isin[13];     // <= 12 chars
87	    uint32_t round_lot;
88	    uint32_t tick_table_id;
89	    uint8_t price_decimals;
90	    uint32_t upper_limit;
91	    uint32_t lower_limit;
92	    uint8_t flags;     // FLAG_* bits
93	
94	    // state section (T2)
95	    char trading_state;           // 'T'/'V'/'?'
96	    char short_sell_restriction;  // '0'/'1'/'?'
97	    uint32_t reference_price;     // may be NO_PRICE
98	    char last_system_event;       // O/S/Q/M/E/C, '\0' = none
99	
100	    // book section (T4)
101	    uint8_t level_count_bid;  // 0..10
102	    uint8_t level_count_ask;  // 0..10
103	    BookLevel bids[BOOK_DEPTH];  // best (highest) first
104	    BookLevel asks[BOOK_DEPTH];  // best (lowest) first
105	    uint64_t total_bid_qty;      // whole book, not just top 10
106	    uint64_t total_ask_qty;
107	    uint32_t total_bid_orders;
108	    uint32_t total_ask_orders;
109	
110	    // trade summary section (T5, no tape)
111	    uint32_t last_price;
112	    uint32_t last_qty;
113	    uint64_t last_match_number;
114	    uint64_t last_trade_ns;
115	    uint64_t cum_qty;
116	    uint64_t cum_turnover;
117	    uint32_t trade_count;
118	
119	    // delta section (T3 mutation)
120	    char delta_op;  // 'A'/'E'/'D'/'U'/'#'
121	    uint64_t delta_order_number;
122	    uint64_t delta_orig_order_number;  // 'U' only, else 0
123	    char delta_side;                   // 'B'/'S', '\0' when op '#'
124	    uint32_t delta_price;
125	    uint32_t delta_qty;
126	    char delta_order_type;  // 'Q' = DLP, ' ' = plain, '\0' when op '#'
127	
128	    UpdateRecord();
129	};
130	
131	// --- ORDER / TICK / HELLO / SYNC_END ---------------------------------------
132	
133	struct OrderRecord {
134	    uint64_t order_number;
135	    char ticker[5];
136	    char group[5];
137	    char side;  // 'B'/'S'
138	    uint32_t price;
139	    uint32_t qty_remaining;
140	    char order_type;  // 'Q' = DLP, ' ' = plain
141	
142	    OrderRecord();
143	};
144	
145	struct TickRecord {
146	    uint32_t table_id;
147	    uint32_t price_start;
148	    uint32_t tick_size;
149	
150	    TickRecord() : table_id(0), price_start(0), tick_size(0) {}
151	};
152	
153	struct HelloRecord {
154	    uint64_t epoch;          // 0 = fresh FH / empty DB
155	    uint64_t last_exch_seq;  // 0 = none
156	
157	    HelloRecord() : epoch(0), last_exch_seq(0) {}
158	};
159	
160	struct SyncEndRecord {
161	    char session[11];  // <= 10 chars
162	    uint64_t last_exch_seq;
163	    uint64_t epoch;
164	
165	    SyncEndRecord();
166	};
167	
168	// --- encode ------------------------------------------------------------------
169	// Each writes header + body into buf (caller provides >= the kind's
170	// *_WIRE_SIZE bytes) and returns total bytes written. All padding and
171	// unused regions are zero-filled.
172	
173	size_t encode_update(const UpdateRecord& in, unsigned char* buf);
174	size_t encode_order(const OrderRecord& in, unsigned char* buf);
175	size_t encode_tick(const TickRecord& in, unsigned char* buf);
176	size_t encode_hello(const HelloRecord& in, unsigned char* buf);
177	size_t encode_sync_end(const SyncEndRecord& in, unsigned char* buf);
178	// Body-less kinds: KIND_SYNC_BEGIN, KIND_GET_STATE, KIND_RESET.
179	// Returns 0 if kind is not one of those three.
180	size_t encode_control(char kind, unsigned char* buf);
181	
182	// --- decode ------------------------------------------------------------------
183	// Strict: validate magic, version, kind, and body_len == the kind's fixed
184	// size; len must equal the kind's total wire size. On failure return false
185	// and, if err != NULL, point *err at a static reason string.
186	
187	// Validates a header and returns its kind through *kind (buf must hold
188	// >= RECORD_HEADER_SIZE bytes). body_len is returned through *body_len.
189	bool decode_header(const unsigned char* buf, size_t len, char* kind,
190	                   uint16_t* body_len, const char** err);
191	
192	bool decode_update(const unsigned char* buf, size_t len, UpdateRecord& out,
193	                   const char** err);
194	bool decode_order(const unsigned char* buf, size_t len, OrderRecord& out,
195	                  const char** err);
196	bool decode_tick(const unsigned char* buf, size_t len, TickRecord& out,
197	                 const char** err);
198	bool decode_hello(const unsigned char* buf, size_t len, HelloRecord& out,
199	                  const char** err);
200	bool decode_sync_end(const unsigned char* buf, size_t len, SyncEndRecord& out,
201	                     const char** err);
202	
203	// --- stream framer -------------------------------------------------------------
204	// Incremental reassembler for the UDS stream (concatenated records — the
205	// header's body_len delimits; no extra length prefix). Same interface
206	// pattern as SoupFramer: feed() bytes as they arrive (byte-at-a-time safe,
207	// header may be split across feeds), pull complete records with next().
208	//
209	// A header that fails validation (bad magic/version/kind/body_len) marks
210	// the stream corrupt: the buffer is discarded, next() returns false
211	// forever, and corrupt() turns true. A corrupt record stream is
212	// unrecoverable by design (docs/wire_spec.md) — the connection owner
213	// must close and start a fresh framer on reconnect.
214	
215	struct RawRecord {
216	    char kind;
217	    std::vector<unsigned char> body;  // owned copy, body_len bytes
218	
219	    RawRecord() : kind('\0') {}
220	};
