229	    // stream is corrupt).
230	    bool next(RawRecord& out);
231	
232	    bool corrupt() const { return corrupt_; }
233	    // Reason the stream was marked corrupt (static string), or NULL.
234	    const char* corrupt_reason() const { return corrupt_reason_; }
235	
236	private:
237	    std::vector<unsigned char> buf_;
238	    bool corrupt_;
239	    const char* corrupt_reason_;
240	};
