    if (it == levels_.end() || it->second < qty) {
        return false; // would go negative — upstream logic error
    }
    it->second -= qty;
    if (it->second == 0) {
        levels_.erase(it);
    }
    return true;
}

uint64_t SideLevels::total_qty() const {
    uint64_t total = 0;
    for (LevelMap::const_iterator it = levels_.begin(); it != levels_.end();
         ++it) {
        total += it->second;
    }
    return total;
}

} // namespace jnx

