1	// orders.cpp — see orders.h. Mirrors jnxfeed/book/orderbook.py exactly.
2	#include "market/orders.h"
3	
4	#include "common/log.h"
5	
6	namespace jnx {
7	
8	Book& OrderBookStore::book(const std::string& orderbook_id) {
9	    std::map<std::string, Book>::iterator it = books_.find(orderbook_id);
10	    if (it == books_.end()) {
11	        it = books_.insert(std::make_pair(orderbook_id, Book(orderbook_id)))
12	                 .first;
13	    }
14	    return it->second;
15	}
16	
17	bool OrderBookStore::apply(const ItchMsg& msg, Execution& execution) {
18	    switch (msg.type) {
19	        case 'A':
20	        case 'F':
21	            if (msg.order_number == 0) {
22	                // Reference-price pseudo-order (§3.3(1)) — refdata's
23	                // business. Count so misrouting shows up.
24	                ++ref_price_ignored;
25	                return false;
26	            }
27	            insert(msg.order_number, msg.orderbook_id, msg.group, msg.side,
28	                   msg.price, msg.qty);
29	            return false;
30	        case 'E':
31	            return execute(msg, execution);
32	        case 'D':
33	            erase(msg);
34	            return false;
35	        case 'U':
36	            replace(msg);
37	            return false;
38	        default:
39	            return false;
40	    }
41	}
42	
43	void OrderBookStore::insert(uint64_t order_number,
44	                            const std::string& orderbook_id,
45	                            const std::string& group, char side,
46	                            uint32_t price, uint32_t qty) {
47	    std::unordered_map<uint64_t, Order>::iterator it =
48	        orders_.find(order_number);
49	    if (it != orders_.end()) {
50	        // §3.3(3): cross-group collision on a combined feed. Count + warn
51	        // and replace the stale record (keeping both corrupts the levels).
52	        ++collisions;
53	        LOG_WARN("orders") << "order number collision: #" << order_number
54	                           << " already live (" << it->second.orderbook_id
55	                           << "), replacing with " << orderbook_id << " "
56	                           << side << " " << qty << "@" << price;
57	        remove_order(it->second);
58	    }
59	    Order order;
60	    order.order_number = order_number;
61	    order.orderbook_id = orderbook_id;
62	    order.group = group;
63	    order.side = side;
64	    order.price = price;
65	    order.remaining_qty = qty;
66	    orders_[order_number] = order;
67	    book(orderbook_id).add(side, price, qty);
68	}
69	
70	void OrderBookStore::remove_order(const Order& order) {
71	    // Copy the fields we need before erasing (order may reference the
72	    // stored object).
73	    std::string oid = order.orderbook_id;
74	    char side = order.side;
75	    uint32_t price = order.price;
76	    uint32_t rem = order.remaining_qty;
77	    orders_.erase(order.order_number);
78	    book(oid).remove(side, price, rem);
79	}
80	
81	bool OrderBookStore::execute(const ItchMsg& msg, Execution& execution) {
82	    std::unordered_map<uint64_t, Order>::iterator it =
83	        orders_.find(msg.order_number);
84	    if (it == orders_.end()) {
85	        ++orphan_executes;
86	        return false;
87	    }
88	    Order& order = it->second;
89	    uint32_t qty = msg.executed_qty;
90	    if (qty > order.remaining_qty) {
91	        // Should not happen on a clean feed; clamp so levels never go
92	        // negative, and make it loud.
93	        LOG_WARN("orders") << "execution of " << qty << " exceeds remaining "
94	                           << order.remaining_qty << " on #"
95	                           << order.order_number << "; clamping";
96	        ++clamped_executions;
97	        qty = order.remaining_qty;
98	    }
99	    order.remaining_qty -= qty;
100	    book(order.orderbook_id).remove(order.side, order.price, qty);
101	    execution.orderbook_id = order.orderbook_id;
102	    execution.group = order.group;
103	    execution.side = order.side;
104	    execution.price = order.price;
105	    execution.qty = qty;
106	    execution.match_number = msg.match_number;
107	    if (order.remaining_qty == 0) {
108	        orders_.erase(it);
109	    }
110	    executed_volume += qty;
111	    ++execution_count;
112	    return true;
113	}
114	
115	void OrderBookStore::erase(const ItchMsg& msg) {
116	    std::unordered_map<uint64_t, Order>::iterator it =
117	        orders_.find(msg.order_number);
118	    if (it == orders_.end()) {
119	        ++orphan_deletes;
120	        return;
121	    }
122	    remove_order(it->second);
123	}
124	
125	void OrderBookStore::replace(const ItchMsg& msg) {
126	    std::unordered_map<uint64_t, Order>::iterator it =
127	        orders_.find(msg.orig_order_number);
128	    if (it == orders_.end()) {
129	        // Without the original we know neither book nor side, so the new
130	        // order cannot be placed either (§3.3(2)).
131	        ++orphan_replaces;
132	        return;
133	    }
134	    // Copy inherited fields before removal invalidates the reference.
135	    std::string oid = it->second.orderbook_id;
136	    std::string group = it->second.group;
137	    char side = it->second.side;
138	    remove_order(it->second);
139	    insert(msg.new_order_number, oid, group, side, msg.price, msg.qty);
140	}
141	
142	} // namespace jnx
