// reactor.h — minimal single-threaded poll() event loop with monotonic
// timers (C++ port of jnxfeed/net/reactor.py semantics):
//
// - set_read(fd, cb) / set_write(fd, cb) — independent read/write interest
//   per fd; a null function clears that interest; remove(fd) drops both.
// - call_later(delay_ns, cb) -> id; cancel(id). Timers fire in deadline
//   order (ties in scheduling order), based on CLOCK_MONOTONIC.
// - run() loops until stop(); stop() is safe from within any callback.
#ifndef JNX_FH_REACTOR_H
#define JNX_FH_REACTOR_H

#include <cstdint>
#include <functional>
#include <map>
#include <utility>

namespace jnx {

class Reactor {
public:
    typedef std::function<void()> Callback;

    Reactor() : next_timer_id_(1), running_(false) {}

    // Register/replace the read (write) callback for fd; an empty
    // std::function clears the interest.
    void set_read(int fd, Callback cb);
    void set_write(int fd, Callback cb);
    void remove(int fd);

    // Schedule cb to run once after delay_ns (monotonic). Returns a
    // cancellation id (never 0).
    uint64_t call_later(uint64_t delay_ns, Callback cb);
    void cancel(uint64_t timer_id);

    void run();
    void stop() { running_ = false; }

private:
    struct FdInterest {
        Callback on_read;
        Callback on_write;
    };
    // key: (deadline_ns, timer_id) — deadline order, scheduling order ties.
    typedef std::map<std::pair<uint64_t, uint64_t>, Callback> TimerMap;

    std::map<int, FdInterest> fds_;
    TimerMap timers_;
    uint64_t next_timer_id_;
    bool running_;
};

} // namespace jnx

#endif // JNX_FH_REACTOR_H

// reactor.cpp — see reactor.h.
#include "fh/reactor.h"

#include <poll.h>

#include <vector>

#include "common/time.h"

namespace jnx {

void Reactor::set_read(int fd, Callback cb) {
    if (!cb && fds_.count(fd) && !fds_[fd].on_write) {
        fds_.erase(fd);
        return;
    }
    fds_[fd].on_read = cb;
}

void Reactor::set_write(int fd, Callback cb) {
    if (!cb && fds_.count(fd) && !fds_[fd].on_read) {
        fds_.erase(fd);
        return;
    }
    fds_[fd].on_write = cb;
}

void Reactor::remove(int fd) {
    fds_.erase(fd);
}

uint64_t Reactor::call_later(uint64_t delay_ns, Callback cb) {
    uint64_t id = next_timer_id_++;
    timers_[std::make_pair(mono_ns() + delay_ns, id)] = cb;
    return id;
}

void Reactor::cancel(uint64_t timer_id) {
    for (TimerMap::iterator it = timers_.begin(); it != timers_.end(); ++it) {
        if (it->first.second == timer_id) {
            timers_.erase(it);
            return;
        }
    }
}

void Reactor::run() {
    running_ = true;
    std::vector<struct pollfd> pfds;
    std::vector<int> fd_order;
    while (running_) {
        if (fds_.empty() && timers_.empty()) {
            break; // nothing left to drive
        }
        // Timeout: until the earliest timer, capped at 200 ms so stop()
        // from a signal-checking timer stays responsive.
        int timeout_ms = 200;
        if (!timers_.empty()) {
            uint64_t now = mono_ns();
            uint64_t deadline = timers_.begin()->first.first;
            uint64_t wait_ms =
                deadline > now ? (deadline - now) / 1000000ULL : 0;
            if (wait_ms < static_cast<uint64_t>(timeout_ms)) {
                timeout_ms = static_cast<int>(wait_ms);
            }
        }

        pfds.clear();
        fd_order.clear();
        for (std::map<int, FdInterest>::const_iterator it = fds_.begin();
             it != fds_.end(); ++it) {
            struct pollfd p;
            p.fd = it->first;
            p.events = 0;
            p.revents = 0;
            if (it->second.on_read) p.events |= POLLIN;
            if (it->second.on_write) p.events |= POLLOUT;
            pfds.push_back(p);
            fd_order.push_back(it->first);
        }

        int n = ::poll(pfds.empty() ? NULL : &pfds[0],
                       static_cast<nfds_t>(pfds.size()), timeout_ms);
        if (n > 0) {
            for (size_t i = 0; i < pfds.size() && running_; ++i) {
                short re = pfds[i].revents;
                if (re == 0) continue;
                std::map<int, FdInterest>::iterator it =
                    fds_.find(fd_order[i]);
                if (it == fds_.end()) continue; // removed by a callback
                if ((re & (POLLIN | POLLERR | POLLHUP)) && it->second.on_read) {
                    Callback cb = it->second.on_read;
                    cb();
                    it = fds_.find(fd_order[i]);
                    if (it == fds_.end()) continue;
                }
                if ((re & (POLLOUT | POLLERR)) && it->second.on_write) {
                    Callback cb = it->second.on_write;
                    cb();
                }
            }
        }

        // Fire due timers (copy out first: callbacks may schedule/cancel).
        uint64_t now = mono_ns();
        while (running_ && !timers_.empty() &&
               timers_.begin()->first.first <= now) {
            Callback cb = timers_.begin()->second;
            timers_.erase(timers_.begin());
            cb();
        }
    }
    running_ = false;
}

} // namespace jnx

// soupclient.h — SoupBinTCP client:
//
// - SoupClientSession: sans-I/O session state machine, a direct port of
//   jnxfeed/soup/session.py. Fed received bytes + a periodic clock tick;
//   produces output bytes; reports events through std::function callbacks.
//   Sequence numbering is self-counted from the Login-Accepted value
//   (Soup carries no per-message seq).
// - TcpSoupConnector: reactor-driven TCP glue with reconnect (1 s backoff
//   doubling, capped 10 s), re-logging-in with the SAME session id at the
//   next expected seq (lossless resume). Login-Rejected is terminal (no
//   retry storm) — surfaced via the session's on_login_rejected.
#ifndef JNX_FH_SOUPCLIENT_H
#define JNX_FH_SOUPCLIENT_H

#include <cstdint>
#include <functional>
#include <string>
#include <vector>

#include "fh/reactor.h"
#include "soup/soup.h"

namespace jnx {

const uint64_t SOUP_HEARTBEAT_NS = 1000000000ULL;        // 1 s outbound idle
const uint64_t SOUP_SILENCE_TIMEOUT_NS = 15000000000ULL; // 15 s inbound idle

class SoupClientSession {
public:
    enum State { ST_CONNECTED, ST_LOGIN_SENT, ST_LIVE, ST_ENDED, ST_FAILED };

    SoupClientSession(const std::string& username,
                      const std::string& password,
                      const std::string& requested_session = "",
                      uint64_t requested_seq = 1);

    // Event callbacks (any may be left empty).
    std::function<void(const std::string&, uint64_t)> on_login_accepted;
    std::function<void(char)> on_login_rejected;
    std::function<void(uint64_t, const unsigned char*, size_t)> on_message;
    std::function<void()> on_end_of_session;
    std::function<void()> on_peer_silent;

    // Prepare for reuse on a fresh TCP connection: keeps the resume point
    // (session_id/next_seq), clears framing/output/timing state.
    void reset();

    // Queue the Login Request (call once the TCP connection is up). Uses
    // the maintained resume point.
    void start(uint64_t now_ns);

    // Override the resume point before start() (bootstrap paths).
    void set_resume(const std::string& session_id, uint64_t next_seq);

    void logout(uint64_t now_ns);

    // Feed received bytes; fires callbacks synchronously.
    void on_bytes(const unsigned char* data, size_t len, uint64_t now_ns);

    // Periodic clock: client heartbeat after 1 s outbound silence; fires
    // on_peer_silent after 15 s inbound silence.
    void on_tick(uint64_t now_ns);

    // Append pending output bytes to out and clear the buffer. Returns
    // true if anything was appended.
    bool take_output(std::vector<unsigned char>& out);
    bool has_output() const { return !out_.empty(); }

    State state() const { return state_; }
    char reject_code() const { return reject_code_; }
    const std::string& session_id() const { return session_id_; }
    uint64_t next_seq() const { return next_seq_; }

private:
    void handle_packet(const SoupPacket& pkt, uint64_t now_ns);

    std::string username_;
    std::string password_;
    std::string session_id_; // resume point, survives reset()
    uint64_t next_seq_;      // resume point, survives reset()

    State state_;
    char reject_code_;
    SoupFramer framer_;
    std::vector<unsigned char> out_;
    uint64_t last_sent_ns_;     // 0 = never
    uint64_t last_received_ns_; // 0 = never
};

// Reactor-driven TCP transport for a SoupClientSession.
class TcpSoupConnector {
public:
    TcpSoupConnector(Reactor& reactor, const std::string& host, int port,
                     SoupClientSession& session);

    // Called after every unplanned connection loss (before the retry is
    // scheduled) — informational.
    std::function<void()> on_disconnect;

    void start();  // first connect attempt
    void stop();   // close + cancel timers (terminal)
    // Push session output to the socket now (call after queuing packets).
    void flush();
    // Force a reconnect cycle (e.g. peer-silent).
    void reconnect();

    bool connected() const { return fd_ >= 0 && established_; }

private:
    void attempt_connect();
    void on_connect_writable();
    void on_readable();
    void on_writable();
    void handle_disconnect(const char* why);
    void schedule_retry();
    void schedule_tick();
    void close_fd();

    Reactor& reactor_;
    std::string host_;
    int port_;
    SoupClientSession& session_;
    int fd_;
    bool established_;
    bool stopped_;
    uint64_t backoff_ns_;
    uint64_t retry_timer_;
    uint64_t tick_timer_;
    std::vector<unsigned char> sendbuf_; // unwritten tail
};

} // namespace jnx

#endif // JNX_FH_SOUPCLIENT_H

// soupclient.cpp — see soupclient.h.
#include "fh/soupclient.h"

#include <arpa/inet.h>
#include <errno.h>
#include <fcntl.h>
#include <netinet/in.h>
#include <netinet/tcp.h>
#include <sys/socket.h>
#include <unistd.h>

#include <cstring>

#include "common/log.h"
#include "common/time.h"

namespace jnx {

static const char* COMP = "soup";

// --- SoupClientSession -----------------------------------------------------

SoupClientSession::SoupClientSession(const std::string& username,
                                     const std::string& password,
                                     const std::string& requested_session,
                                     uint64_t requested_seq)
    : username_(username),
      password_(password),
      session_id_(requested_session),
      next_seq_(requested_seq),
      state_(ST_CONNECTED),
      reject_code_('\0'),
      last_sent_ns_(0),
      last_received_ns_(0) {}

void SoupClientSession::reset() {
    framer_ = SoupFramer();
    out_.clear();
    state_ = ST_CONNECTED;
    reject_code_ = '\0';
    last_sent_ns_ = 0;
    last_received_ns_ = 0;
}

void SoupClientSession::set_resume(const std::string& session_id,
                                   uint64_t next_seq) {
    session_id_ = session_id;
    next_seq_ = next_seq;
}

void SoupClientSession::start(uint64_t now_ns) {
    SoupLoginRequest req;
    std::snprintf(req.username, sizeof(req.username), "%s",
                  username_.c_str());
    std::snprintf(req.password, sizeof(req.password), "%s",
                  password_.c_str());
    std::snprintf(req.requested_session, sizeof(req.requested_session), "%s",
                  session_id_.c_str());
    req.requested_sequence = next_seq_;
    unsigned char buf[SOUP_LOGIN_REQUEST_WIRE];
    size_t n = soup_build_login_request(req, buf);
    out_.insert(out_.end(), buf, buf + n);
    last_sent_ns_ = now_ns;
    state_ = ST_LOGIN_SENT;
}

void SoupClientSession::logout(uint64_t now_ns) {
    unsigned char buf[SOUP_BARE_WIRE];
    size_t n = soup_build_packet('O', NULL, 0, buf);
    out_.insert(out_.end(), buf, buf + n);
    last_sent_ns_ = now_ns;
}

void SoupClientSession::on_bytes(const unsigned char* data, size_t len,
                                 uint64_t now_ns) {
    last_received_ns_ = now_ns;
    framer_.feed(data, len);
    SoupPacket pkt;
    while (framer_.next(pkt)) {
        handle_packet(pkt, now_ns);
    }
}

void SoupClientSession::handle_packet(const SoupPacket& pkt,
                                      uint64_t now_ns) {
    (void)now_ns;
    const unsigned char* payload =
        pkt.payload.empty() ? NULL : &pkt.payload[0];
    switch (pkt.type) {
        case 'A': {
            SoupLoginAccepted la;
            const char* err = NULL;
            if (!soup_parse_login_accepted(payload, pkt.payload.size(), la,
                                           &err)) {
                LOG_WARN(COMP) << "bad LoginAccepted: " << (err ? err : "?");
                return;
            }
            session_id_ = la.session;
            next_seq_ = la.sequence;
            state_ = ST_LIVE;
            if (on_login_accepted) on_login_accepted(session_id_, next_seq_);
            return;
        }
        case 'J': {
            SoupLoginRejected rj;
            const char* err = NULL;
            if (soup_parse_login_rejected(payload, pkt.payload.size(), rj,
                                          &err)) {
                reject_code_ = rj.reject_code;
            }
            state_ = ST_FAILED;
            if (on_login_rejected) on_login_rejected(reject_code_);
            return;
        }
        case 'S': {
            uint64_t seq = next_seq_++;
            if (on_message) on_message(seq, payload, pkt.payload.size());
            return;
        }
        case 'H':
            return; // inbound byte already refreshed last_received_ns_
        case 'Z':
            state_ = ST_ENDED;
            if (on_end_of_session) on_end_of_session();
            return;
        case '+':
            return; // debug packet: ignore
        default:
            return; // never sent by a well-behaved server; ignore
    }
}

void SoupClientSession::on_tick(uint64_t now_ns) {
    if (state_ != ST_LOGIN_SENT && state_ != ST_LIVE) {
        return;
    }
    if (last_received_ns_ != 0 &&
        now_ns - last_received_ns_ >= SOUP_SILENCE_TIMEOUT_NS) {
        if (on_peer_silent) on_peer_silent();
        return;
    }
    if (last_sent_ns_ != 0 && now_ns - last_sent_ns_ >= SOUP_HEARTBEAT_NS) {
        unsigned char buf[SOUP_BARE_WIRE];
        size_t n = soup_build_packet('R', NULL, 0, buf);
        out_.insert(out_.end(), buf, buf + n);
        last_sent_ns_ = now_ns;
    }
}

bool SoupClientSession::take_output(std::vector<unsigned char>& out) {
    if (out_.empty()) {
        return false;
    }
    out.insert(out.end(), out_.begin(), out_.end());
    out_.clear();
    return true;
}

// --- TcpSoupConnector --------------------------------------------------------

TcpSoupConnector::TcpSoupConnector(Reactor& reactor, const std::string& host,
                                   int port, SoupClientSession& session)
    : reactor_(reactor),
      host_(host),
      port_(port),
      session_(session),
      fd_(-1),
      established_(false),
      stopped_(false),
      backoff_ns_(1000000000ULL),
      retry_timer_(0),
      tick_timer_(0) {}

void TcpSoupConnector::start() {
    attempt_connect();
}

void TcpSoupConnector::stop() {
    stopped_ = true;
    if (retry_timer_) reactor_.cancel(retry_timer_);
    if (tick_timer_) reactor_.cancel(tick_timer_);
    retry_timer_ = tick_timer_ = 0;
    close_fd();
}

void TcpSoupConnector::close_fd() {
    if (fd_ >= 0) {
        reactor_.remove(fd_);
        ::close(fd_);
        fd_ = -1;
    }
    established_ = false;
    sendbuf_.clear();
}

void TcpSoupConnector::attempt_connect() {
    if (stopped_) return;
    fd_ = ::socket(AF_INET, SOCK_STREAM | SOCK_NONBLOCK, 0);
    if (fd_ < 0) {
        LOG_ERROR(COMP) << "socket: " << std::strerror(errno);
        schedule_retry();
        return;
    }
    int one = 1;
    ::setsockopt(fd_, IPPROTO_TCP, TCP_NODELAY, &one, sizeof(one));
    struct sockaddr_in addr;
    std::memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons(static_cast<uint16_t>(port_));
    if (::inet_pton(AF_INET, host_.c_str(), &addr.sin_addr) != 1) {
        LOG_ERROR(COMP) << "bad host address: " << host_;
        close_fd();
        schedule_retry();
        return;
    }
    int rc = ::connect(fd_, reinterpret_cast<struct sockaddr*>(&addr),
                       sizeof(addr));
    if (rc == 0) {
        on_connect_writable();
        return;
    }
    if (errno != EINPROGRESS) {
        LOG_WARN(COMP) << "connect " << host_ << ":" << port_ << ": "
                       << std::strerror(errno);
        close_fd();
        schedule_retry();
        return;
    }
    // Completion signalled by writability.
    TcpSoupConnector* self = this;
    reactor_.set_write(fd_, [self]() { self->on_connect_writable(); });
}

void TcpSoupConnector::on_connect_writable() {
    int err = 0;
    socklen_t elen = sizeof(err);
    ::getsockopt(fd_, SOL_SOCKET, SO_ERROR, &err, &elen);
    if (err != 0) {
        LOG_WARN(COMP) << "connect " << host_ << ":" << port_ << ": "
                       << std::strerror(err);
        close_fd();
        schedule_retry();
        return;
    }
    established_ = true;
    backoff_ns_ = 1000000000ULL; // reset backoff on a successful connect
    LOG_INFO(COMP) << "connected to " << host_ << ":" << port_
                   << ", logging in (session='" << session_.session_id()
                   << "' seq=" << session_.next_seq() << ")";
    reactor_.set_write(fd_, Reactor::Callback());
    TcpSoupConnector* self = this;
    reactor_.set_read(fd_, [self]() { self->on_readable(); });
    session_.reset();
    session_.start(mono_ns());
    flush();
    schedule_tick();
}

void TcpSoupConnector::on_readable() {
    unsigned char buf[65536];
    for (;;) {
        ssize_t n = ::recv(fd_, buf, sizeof(buf), 0);
        if (n > 0) {
            session_.on_bytes(buf, static_cast<size_t>(n), mono_ns());
            if (session_.state() == SoupClientSession::ST_ENDED ||
                session_.state() == SoupClientSession::ST_FAILED) {
                flush(); // let a queued logout out before the owner acts
                return;
            }
            continue;
        }
        if (n == 0) {
            handle_disconnect("peer closed");
            return;
        }
        if (errno == EAGAIN || errno == EWOULDBLOCK) {
            break;
        }
        if (errno == EINTR) {
            continue;
        }
        handle_disconnect(std::strerror(errno));
        return;
    }
    flush();
}

void TcpSoupConnector::flush() {
    if (fd_ < 0 || !established_) return;
    session_.take_output(sendbuf_);
    while (!sendbuf_.empty()) {
        ssize_t n = ::send(fd_, &sendbuf_[0], sendbuf_.size(), MSG_NOSIGNAL);
        if (n > 0) {
            sendbuf_.erase(sendbuf_.begin(), sendbuf_.begin() + n);
            continue;
        }
        if (n < 0 && (errno == EAGAIN || errno == EWOULDBLOCK)) {
            TcpSoupConnector* self = this;
            reactor_.set_write(fd_, [self]() { self->on_writable(); });
            return;
        }
        if (n < 0 && errno == EINTR) {
            continue;
        }
        handle_disconnect(std::strerror(errno));
        return;
    }
    if (fd_ >= 0) {
        reactor_.set_write(fd_, Reactor::Callback());
    }
}

void TcpSoupConnector::on_writable() {
    reactor_.set_write(fd_, Reactor::Callback());
    flush();
}

void TcpSoupConnector::reconnect() {
    handle_disconnect("forced reconnect");
}

void TcpSoupConnector::handle_disconnect(const char* why) {
    if (stopped_) return;
    LOG_WARN(COMP) << "connection lost (" << why << "); retrying in "
                   << backoff_ns_ / 1000000ULL << " ms";
    close_fd();
    if (tick_timer_) {
        reactor_.cancel(tick_timer_);
        tick_timer_ = 0;
    }
    if (on_disconnect) on_disconnect();
    schedule_retry();
}

void TcpSoupConnector::schedule_retry() {
    if (stopped_) return;
    TcpSoupConnector* self = this;
    retry_timer_ = reactor_.call_later(backoff_ns_, [self]() {
        self->retry_timer_ = 0;
        self->attempt_connect();
    });
    backoff_ns_ *= 2;
    if (backoff_ns_ > 10000000000ULL) {
        backoff_ns_ = 10000000000ULL; // cap 10 s
    }
}

void TcpSoupConnector::schedule_tick() {
    if (stopped_ || fd_ < 0) return;
    TcpSoupConnector* self = this;
    tick_timer_ = reactor_.call_later(250000000ULL, [self]() {
        self->tick_timer_ = 0;
        if (self->fd_ < 0) return;
        self->session_.on_tick(mono_ns());
        self->flush();
        self->schedule_tick();
    });
}

} // namespace jnx

// glimpse.h — GLIMPSE snapshot bootstrap (JNX_PLAN.md §3.5).
//
// Synchronous by design: bootstrap happens strictly before the live
// reactor phase, so a blocking socket with timeouts is the simplest
// correct implementation. Logs in with a BLANK requested session and
// seq 1, applies every snapshot ITCH message to the Market, and returns
// when the `G` End of Snapshot arrives.
#ifndef JNX_FH_GLIMPSE_H
#define JNX_FH_GLIMPSE_H

#include <cstdint>
#include <string>

#include "market/market.h"

namespace jnx {

struct GlimpseResult {
    std::string session;    // session id from Login Accepted
    uint64_t next_live_seq; // from the G message
    uint64_t message_count; // snapshot messages applied (excluding G)

    GlimpseResult() : next_live_seq(0), message_count(0) {}
};

// Returns false with *err (static string) on failure: connect/login
// rejected/connection lost before G/timeout. Applies snapshot messages
// into `market` (a failure can leave it partially filled — callers retry
// with a FRESH Market).
bool glimpse_bootstrap(const std::string& host, int port,
                       const std::string& username,
                       const std::string& password, Market& market,
                       GlimpseResult& out, const char** err,
                       uint64_t timeout_ns = 30000000000ULL);

} // namespace jnx

#endif // JNX_FH_GLIMPSE_H

// glimpse.cpp — see glimpse.h.
#include "fh/glimpse.h"

#include <arpa/inet.h>
#include <errno.h>
#include <netinet/in.h>
#include <sys/socket.h>
#include <sys/time.h>
#include <unistd.h>

#include <cstring>

#include "common/log.h"
#include "common/time.h"
#include "itch/itch.h"
#include "soup/soup.h"

namespace jnx {

static const char* COMP = "glimpse";

bool glimpse_bootstrap(const std::string& host, int port,
                       const std::string& username,
                       const std::string& password, Market& market,
                       GlimpseResult& out, const char** err,
                       uint64_t timeout_ns) {
    int fd = ::socket(AF_INET, SOCK_STREAM, 0);
    if (fd < 0) {
        if (err) *err = "socket() failed";
        return false;
    }
    struct timeval tv;
    tv.tv_sec = 1;
    tv.tv_usec = 0;
    ::setsockopt(fd, SOL_SOCKET, SO_RCVTIMEO, &tv, sizeof(tv));
    tv.tv_sec = 5;
    ::setsockopt(fd, SOL_SOCKET, SO_SNDTIMEO, &tv, sizeof(tv));

    struct sockaddr_in addr;
    std::memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons(static_cast<uint16_t>(port));
    if (::inet_pton(AF_INET, host.c_str(), &addr.sin_addr) != 1) {
        ::close(fd);
        if (err) *err = "bad glimpse host address";
        return false;
    }
    if (::connect(fd, reinterpret_cast<struct sockaddr*>(&addr),
                  sizeof(addr)) != 0) {
        ::close(fd);
        if (err) *err = "glimpse connect failed";
        return false;
    }

    // Login: blank requested session (spec requirement), seq 1.
    SoupLoginRequest req;
    std::snprintf(req.username, sizeof(req.username), "%s", username.c_str());
    std::snprintf(req.password, sizeof(req.password), "%s", password.c_str());
    req.requested_session[0] = '\0';
    req.requested_sequence = 1;
    unsigned char lbuf[SOUP_LOGIN_REQUEST_WIRE];
    size_t ln = soup_build_login_request(req, lbuf);
    if (::send(fd, lbuf, ln, MSG_NOSIGNAL) != static_cast<ssize_t>(ln)) {
        ::close(fd);
        if (err) *err = "glimpse login send failed";
        return false;
    }

    SoupFramer framer;
    unsigned char rbuf[65536];
    uint64_t deadline = mono_ns() + timeout_ns;
    uint64_t last_rx = mono_ns();
    uint64_t last_tx = mono_ns();

    for (;;) {
        if (mono_ns() > deadline) {
            ::close(fd);
            if (err) *err = "glimpse snapshot timeout";
            return false;
        }
        ssize_t n = ::recv(fd, rbuf, sizeof(rbuf), 0);
        if (n == 0) {
            ::close(fd);
            if (err) *err = "glimpse connection lost before end of snapshot";
            return false;
        }
        if (n < 0) {
            if (errno == EAGAIN || errno == EWOULDBLOCK || errno == EINTR) {
                uint64_t now = mono_ns();
                if (now - last_rx > 15000000000ULL) {
                    ::close(fd);
                    if (err) *err = "glimpse peer silent for 15 s";
                    return false;
                }
                if (now - last_tx > 1000000000ULL) {
                    unsigned char hb[SOUP_BARE_WIRE];
                    size_t hn = soup_build_packet('R', NULL, 0, hb);
                    (void)::send(fd, hb, hn, MSG_NOSIGNAL);
                    last_tx = now;
                }
                continue;
            }
            ::close(fd);
            if (err) *err = "glimpse recv error";
            return false;
        }
        last_rx = mono_ns();
        framer.feed(rbuf, static_cast<size_t>(n));

        SoupPacket pkt;
        while (framer.next(pkt)) {
            const unsigned char* payload =
                pkt.payload.empty() ? NULL : &pkt.payload[0];
            if (pkt.type == 'J') {
                ::close(fd);
                if (err) *err = "glimpse login rejected";
                return false;
            }
            if (pkt.type == 'A') {
                SoupLoginAccepted la;
                const char* perr = NULL;
                if (soup_parse_login_accepted(payload, pkt.payload.size(),
                                              la, &perr)) {
                    out.session = la.session;
                    LOG_INFO(COMP) << "logged in, session='" << out.session
                                   << "', receiving snapshot";
                }
                continue;
            }
            if (pkt.type == 'Z') {
                ::close(fd);
                if (err) *err = "glimpse ended before end of snapshot";
                return false;
            }
            if (pkt.type != 'S') {
                continue; // heartbeat/debug
            }
            ItchMsg msg;
            const char* derr = NULL;
            if (!decode(payload, pkt.payload.size(), msg, &derr)) {
                LOG_WARN(COMP) << "undecodable snapshot message: "
                               << (derr ? derr : "?");
                continue;
            }
            if (msg.type == 'G') {
                out.next_live_seq = msg.sequence_number;
                LOG_INFO(COMP) << "end of snapshot: " << out.message_count
                               << " messages, next live seq "
                               << out.next_live_seq;
                // Clean logout, then done.
                unsigned char ob[SOUP_BARE_WIRE];
                size_t on = soup_build_packet('O', NULL, 0, ob);
                (void)::send(fd, ob, on, MSG_NOSIGNAL);
                ::close(fd);
                return true;
            }
            market.apply(msg);
            ++out.message_count;
        }
    }
}

} // namespace jnx

// publish.h — FH output side:
//
// - PubContext: publisher-side per-ticker/group state that the market core
//   deliberately does not track (last system event per group, last trade
//   timestamp per ticker) — fed from ApplyResults and from recovery rows.
// - make_update(): the F3-deferred record builder — assembles one full
//   UpdateRecord (static+state from refdata, top-10 book from the levels,
//   trade summary from the tape, delta from the ApplyResult).
// - build_sync_dump(): RESET-less full dump of a Market as encoded
//   records (SYNC_BEGIN, TICKs, ORDERs, one '#' UPDATE per book, SYNC_END).
// - DbLink: blocking UDS link to jnxdb (SO_SNDTIMEO 5 s) with HELLO
//   handshake; failure marks it disconnected (owner reconnects via a
//   reactor timer — no threads).
// - McastSender: one sendto per UPDATE; IP_MULTICAST_LOOP=1.
#ifndef JNX_FH_PUBLISH_H
#define JNX_FH_PUBLISH_H

#include <cstdint>
#include <map>
#include <string>
#include <vector>

#include "market/market.h"
#include "wire/record.h"

namespace jnx {

struct PubContext {
    // Latest S.event per group; "" key = system-wide (blank-group S).
    std::map<std::string, char> last_sys_event;
    // Exchange timestamp of the last trade per ticker.
    std::map<std::string, uint64_t> last_trade_ns;

    // Record an applied message's contribution (S events, trade ns).
    void note(const ApplyResult& res, uint64_t exch_ns);

    // Latest event applicable to `group` (group-specific wins over
    // system-wide); '\0' = none.
    char event_for(const std::string& group) const;
};

struct Envelope {
    uint64_t epoch;
    uint64_t pub_seq;
    std::string session;
    uint64_t exch_seq;
    uint64_t exch_ns;
    char trigger;

    Envelope() : epoch(0), pub_seq(0), exch_seq(0), exch_ns(0),
                 trigger('\0') {}
};

// Build the full UPDATE for the (ticker, group) named by `res` (empty
// ticker allowed: S/L/orphan triggers produce a state-only record).
UpdateRecord make_update(const Market& market, const PubContext& ctx,
                         const ApplyResult& res, const Envelope& env);

// Encode a full sync dump of `market` into `out` (appended):
// SYNC_BEGIN, all TICK rows, all ORDER rows, one UPDATE per book
// (trigger '#', delta '#'), SYNC_END carrying (session, last_exch_seq,
// epoch). Deterministic order (sorted maps).
void build_sync_dump(const Market& market, const PubContext& ctx,
                     const std::string& session, uint64_t last_exch_seq,
                     uint64_t epoch, std::vector<unsigned char>& out);

class DbLink {
public:
    DbLink() : fd_(-1) {}
    ~DbLink() { close(); }

    // Blocking connect + HELLO handshake. On success fills db_hello with
    // the DB's reply and returns true; on any failure returns false with
    // the link closed.
    bool connect_hello(const std::string& sock_path, uint64_t my_epoch,
                       uint64_t my_last_seq, HelloRecord& db_hello);

    bool connected() const { return fd_ >= 0; }
    int fd() const { return fd_; }
    void close();

    // Blocking write of a full buffer (SO_SNDTIMEO bounds it). On any
    // error: closes the link, returns false.
    bool send(const unsigned char* data, size_t len);

    // Sends GET_STATE and streams the reply records to `cb` until
    // SYNC_END (inclusive). Returns false (link closed) on error/timeout.
    bool get_state(const std::function<void(const RawRecord&)>& cb);

private:
    int fd_;
};

class McastSender {
public:
    McastSender() : fd_(-1), send_errors_(0) {}
    ~McastSender();

    // group: dotted quad (e.g. 239.192.1.1); iface: local interface
    // address ("" = kernel default). Loopback is always enabled.
    bool open(const std::string& group, int port, int ttl,
              const std::string& iface);
    // Best-effort: failures are counted, never fatal.
    void send(const unsigned char* data, size_t len);

    uint64_t send_errors() const { return send_errors_; }

private:
    int fd_;
    struct { unsigned char raw[16]; } addr_storage_;
    size_t addr_len_ = 0;
    uint64_t send_errors_;
};

} // namespace jnx

#endif // JNX_FH_PUBLISH_H

