// recover.h — FH startup recovery (JNX_PLAN2.md §1 restart matrix, row 1):
// rebuild the Market from a jnxdb GET_STATE dump so the FH can resume the
// exchange session at last_seq+1 with zero replay.
#ifndef JNX_FH_RECOVER_H
#define JNX_FH_RECOVER_H

#include <cstdint>
#include <string>

#include "fh/publish.h"
#include "market/market.h"

namespace jnx {

struct RecoveredMeta {
    std::string session;
    uint64_t last_exch_seq;
    uint64_t epoch;

    RecoveredMeta() : last_exch_seq(0), epoch(0) {}
};

// Pulls the full state from an already-connected DbLink (HELLO done) and
// rebuilds `market` + `ctx` from it: TICK rows -> tick tables, ORDER rows
// -> order store + levels, '#' UPDATE rows -> refdata/state/trade summary
// + publisher context. Fills `meta` from the SYNC_END. Returns false on
// stream failure (market may be partially filled — caller starts over
// with a fresh Market / falls back to bootstrap).
bool recover_from_db(DbLink& db, Market& market, PubContext& ctx,
                     RecoveredMeta& meta);

} // namespace jnx

#endif // JNX_FH_RECOVER_H

// recover.cpp — see recover.h.
#include "fh/recover.h"

#include "common/log.h"
#include "wire/record.h"

namespace jnx {

static const char* COMP = "recover";

namespace {

struct RecoveryState {
    Market* market;
    PubContext* ctx;
    RecoveredMeta* meta;
    bool saw_begin;
    bool saw_end;
    uint64_t orders;
    uint64_t ticks;
    uint64_t rows;
    bool error;

    RecoveryState()
        : market(NULL), ctx(NULL), meta(NULL), saw_begin(false),
          saw_end(false), orders(0), ticks(0), rows(0), error(false) {}
};

void apply_record(RecoveryState& st, const RawRecord& raw) {
    const unsigned char* body = raw.body.empty() ? NULL : &raw.body[0];
    // Re-assemble a full wire record for the typed decoders (they take
    // header + body). Cheap and keeps one decode path.
    unsigned char wire[MAX_RECORD_WIRE_SIZE];
    const char* err = NULL;
    switch (raw.kind) {
        case KIND_SYNC_BEGIN:
            st.saw_begin = true;
            return;
        case KIND_TICK: {
            TickRecord t;
            size_t n = RECORD_HEADER_SIZE + raw.body.size();
            encode_tick(t, wire); // writes a valid header
            std::memcpy(wire + RECORD_HEADER_SIZE, body, raw.body.size());
            if (!decode_tick(wire, n, t, &err)) {
                st.error = true;
                return;
            }
            st.market->restore_tick(t.table_id, t.price_start, t.tick_size);
            ++st.ticks;
            return;
        }
        case KIND_ORDER: {
            OrderRecord o;
            size_t n = RECORD_HEADER_SIZE + raw.body.size();
            encode_order(o, wire);
            std::memcpy(wire + RECORD_HEADER_SIZE, body, raw.body.size());
            if (!decode_order(wire, n, o, &err)) {
                st.error = true;
                return;
            }
            st.market->restore_order(o.order_number, o.ticker, o.group,
                                     o.side, o.price, o.qty_remaining,
                                     o.order_type);
            ++st.orders;
            return;
        }
        case KIND_UPDATE: {
            UpdateRecord u;
            size_t n = RECORD_HEADER_SIZE + raw.body.size();
            encode_update(u, wire);
            std::memcpy(wire + RECORD_HEADER_SIZE, body, raw.body.size());
            if (!decode_update(wire, n, u, &err)) {
                st.error = true;
                return;
            }
            std::string ticker(u.ticker);
            std::string group(u.group);
            if (ticker.empty()) {
                return; // S/L pseudo-rows: nothing per-ticker to restore
            }
            bool directory_seen = (u.flags & FLAG_DIRECTORY_SEEN) != 0;
            bool any_state = u.trading_state != '?' ||
                             u.short_sell_restriction != '?' ||
                             u.reference_price != 0;
            if (directory_seen || any_state) {
                st.market->restore_instrument(
                    ticker, group, u.isin, u.round_lot, u.tick_table_id,
                    u.price_decimals, u.upper_limit, u.lower_limit,
                    directory_seen, u.trading_state,
                    u.short_sell_restriction,
                    u.reference_price != 0
                        ? static_cast<int64_t>(u.reference_price)
                        : -1);
            }
            if (u.trade_count > 0) {
                st.market->restore_trades(
                    ticker, u.trade_count, u.cum_qty, u.cum_turnover,
                    static_cast<int64_t>(u.last_price),
                    static_cast<int64_t>(u.last_qty), u.last_match_number);
                if (u.last_trade_ns != 0) {
                    st.ctx->last_trade_ns[ticker] = u.last_trade_ns;
                }
            }
            if (u.last_system_event != '\0') {
                st.ctx->note_event(group, u.last_system_event);
            }
            ++st.rows;
            return;
        }
        case KIND_SYNC_END: {
            SyncEndRecord e;
            size_t n = RECORD_HEADER_SIZE + raw.body.size();
            encode_sync_end(e, wire);
            std::memcpy(wire + RECORD_HEADER_SIZE, body, raw.body.size());
            if (!decode_sync_end(wire, n, e, &err)) {
                st.error = true;
                return;
            }
            st.meta->session = e.session;
            st.meta->last_exch_seq = e.last_exch_seq;
            st.meta->epoch = e.epoch;
            st.saw_end = true;
            return;
        }
        default:
            LOG_WARN(COMP) << "unexpected record kind '" << raw.kind
                           << "' in recovery stream (ignored)";
            return;
    }
}

} // namespace

bool recover_from_db(DbLink& db, Market& market, PubContext& ctx,
                     RecoveredMeta& meta) {
    RecoveryState st;
    st.market = &market;
    st.ctx = &ctx;
    st.meta = &meta;

    bool ok = db.get_state([&st](const RawRecord& rec) {
        if (!st.error) {
            apply_record(st, rec);
        }
    });
    if (!ok || st.error || !st.saw_begin || !st.saw_end) {
        LOG_ERROR(COMP) << "recovery dump failed (ok=" << ok
                        << " error=" << st.error << " begin=" << st.saw_begin
                        << " end=" << st.saw_end << ")";
        return false;
    }
    LOG_INFO(COMP) << "recovered from db: " << st.orders << " orders, "
                   << st.ticks << " tick rows, " << st.rows
                   << " book rows; session='" << meta.session << "' last_seq="
                   << meta.last_exch_seq << " epoch=" << meta.epoch;
    return true;
}

} // namespace jnx

// jnxfh_main.cpp — the jnxfh feed handler process (JNX_PLAN2.md F5).
//
// Flow: cfg -> DB connect + HELLO -> recovery or bootstrap -> live loop
// (reactor): soup packet -> itch decode -> market.apply -> one UPDATE per
// applied message (except 'T') -> DB write FIRST, then multicast send.
// Single-threaded: DB reconnect is a reactor timer, never a thread.
//
// Config keys (file via --config=..., overridden by --key=value):
//   itch_host itch_port glimpse_host glimpse_port user pass
//   db_sock mcast_group mcast_port mcast_ttl mcast_if
//   bootstrap (replay|glimpse)  require_db (0|1)
#include <signal.h>
#include <unistd.h>

#include <cstdio>
#include <cstring>
#include <string>
#include <vector>

#include "common/cfg.h"
#include "common/log.h"
#include "common/time.h"
#include "fh/glimpse.h"
#include "fh/publish.h"
#include "fh/reactor.h"
#include "fh/recover.h"
#include "fh/soupclient.h"
#include "itch/itch.h"
#include "market/market.h"
#include "wire/record.h"

namespace {

const char* COMP = "jnxfh";

volatile sig_atomic_t g_stop = 0;

void on_signal(int) {
    g_stop = 1;
}

struct Fh {
    // config
    std::string db_sock;
    bool require_db;

    // state
    jnx::Market market;
    jnx::PubContext ctx;
    jnx::DbLink db;
    jnx::McastSender mcast;
    uint64_t epoch;
    uint64_t pub_seq;         // last published pub_seq (starts 0, first is 1)
    uint64_t last_exch_seq;   // last APPLIED exchange seq (incl. T)
    std::string session;      // current exchange session id
    bool db_connected;

    // stats
    uint64_t published;
    uint64_t db_write_fails;
    uint64_t decode_errors;
    uint64_t msgs_since_stats;

    int exit_code;

    Fh() : require_db(false), epoch(0), pub_seq(0), last_exch_seq(0),
           db_connected(false), published(0), db_write_fails(0),
           decode_errors(0), msgs_since_stats(0), exit_code(0) {}

    // RESET + full SYNC dump from our own market state.
    bool push_full_sync() {
        std::vector<unsigned char> out;
        unsigned char ctl[jnx::CONTROL_WIRE_SIZE];
        size_t n = jnx::encode_control(jnx::KIND_RESET, ctl);
        out.insert(out.end(), ctl, ctl + n);
        jnx::build_sync_dump(market, ctx, session, last_exch_seq, epoch, out);
        if (!db.send(&out[0], out.size())) {
            db_connected = false;
            return false;
        }
        LOG_INFO(COMP) << "pushed RESET + full sync to db (" << out.size()
                       << " bytes, last_seq=" << last_exch_seq << ")";
        return true;
    }

    // (Re)establish the DB link; on success sync if needed. Returns
    // db_connected.
    bool try_db_connect() {
        jnx::HelloRecord db_hello;
        if (!db.connect_hello(db_sock, epoch, last_exch_seq, db_hello)) {
            return false;
        }
        db_connected = true;
        LOG_INFO(COMP) << "db connected (db epoch=" << db_hello.epoch
                       << " last_seq=" << db_hello.last_exch_seq << ")";
        // Anything other than an exact match of our position means the DB
        // is empty/stale/from another life: rebase it from our state.
        if (db_hello.epoch != epoch ||
            db_hello.last_exch_seq != last_exch_seq) {
            if (!push_full_sync()) {
                return false;
            }
        }
        return db_connected;
    }
};

} // namespace

int main(int argc, char** argv) {
    jnx::Cfg cfg;
    // Optional config file first, then --key=value overrides.
    for (int i = 1; i < argc; ++i) {
        if (std::strncmp(argv[i], "--config=", 9) == 0) {
            if (!cfg.load_file(argv[i] + 9)) {
                std::fprintf(stderr, "jnxfh: cannot read config %s\n",
                             argv[i] + 9);
                return 2;
            }
        }
    }
    cfg.apply_args(argc, argv);

    const std::string itch_host = cfg.get("itch_host", "127.0.0.1");
    const int itch_port = static_cast<int>(cfg.get_int("itch_port", 15001));
    const std::string glimpse_host =
        cfg.get("glimpse_host", cfg.get("itch_host", "127.0.0.1"));
    const int glimpse_port =
        static_cast<int>(cfg.get_int("glimpse_port", 15002));
    const std::string user = cfg.get("user", "TEST");
    const std::string pass = cfg.get("pass", "SECRET");
    const std::string bootstrap = cfg.get("bootstrap", "replay");
    const std::string mcast_group = cfg.get("mcast_group", "239.192.1.1");
    const int mcast_port = static_cast<int>(cfg.get_int("mcast_port", 26400));
    const int mcast_ttl = static_cast<int>(cfg.get_int("mcast_ttl", 1));
    const std::string mcast_if = cfg.get("mcast_if", "");

    Fh fh;
    fh.db_sock = cfg.get("db_sock", "/tmp/jnx-db.sock");
    fh.require_db = cfg.get_int("require_db", 0) != 0;
    fh.epoch = jnx::now_ns(); // provisional; recovery may adopt the DB's

    signal(SIGINT, on_signal);
    signal(SIGTERM, on_signal);
    signal(SIGPIPE, SIG_IGN);

    if (!fh.mcast.open(mcast_group, mcast_port, mcast_ttl, mcast_if)) {
        return 2;
    }

    // ---- startup decision tree (restart matrix) --------------------------
    std::string login_session; // requested session for the ITCH login
    uint64_t login_seq = 1;

    jnx::HelloRecord db_hello;
    bool db_up = fh.db.connect_hello(fh.db_sock, 0, 0, db_hello);
    if (!db_up && fh.require_db) {
        LOG_ERROR(COMP) << "db unavailable at " << fh.db_sock
                        << " and require_db=1";
        return 3;
    }

    if (db_up && (db_hello.epoch != 0 || db_hello.last_exch_seq != 0)) {
        // DB has state: recover and resume (zero replay).
        jnx::RecoveredMeta meta;
        if (recover_from_db(fh.db, fh.market, fh.ctx, meta)) {
            fh.session = meta.session;
            fh.last_exch_seq = meta.last_exch_seq;
            fh.epoch = meta.epoch;
            fh.db_connected = true;
            login_session = meta.session;
            login_seq = meta.last_exch_seq + 1;
            LOG_INFO(COMP) << "resume mode: session='" << login_session
                           << "' seq=" << login_seq;
        } else {
            LOG_ERROR(COMP) << "db recovery failed; falling back to "
                            << bootstrap << " bootstrap with a fresh market";
            fh.market = jnx::Market();
            fh.ctx = jnx::PubContext();
            db_up = fh.db.connect_hello(fh.db_sock, fh.epoch,
                                        fh.last_exch_seq, db_hello);
        }
    }

    if (login_seq == 1 && login_session.empty()) {
        // No recovered state: cold bootstrap.
        if (bootstrap == "glimpse") {
            jnx::GlimpseResult gr;
            const char* err = NULL;
            if (!jnx::glimpse_bootstrap(glimpse_host, glimpse_port, user,
                                        pass, fh.market, gr, &err)) {
                LOG_ERROR(COMP) << "glimpse bootstrap failed: "
                                << (err ? err : "?");
                return 4;
            }
            fh.session = gr.session;
            fh.last_exch_seq = gr.next_live_seq - 1;
            login_session = ""; // blank = current session (spec-safe)
            login_seq = gr.next_live_seq;
        } else if (bootstrap == "replay") {
            login_session = "";
            login_seq = 1;
            fh.last_exch_seq = 0;
        } else {
            LOG_ERROR(COMP) << "unknown bootstrap mode: " << bootstrap;
            return 2;
        }
        if (db_up) {
            fh.db_connected = true;
            if (!fh.push_full_sync()) {
                LOG_WARN(COMP) << "initial sync failed; will retry";
            }
        }
    }

    // ---- live loop --------------------------------------------------------
    jnx::Reactor reactor;
    jnx::SoupClientSession session(user, pass, login_session, login_seq);
    jnx::TcpSoupConnector connector(reactor, itch_host, itch_port, session);

    session.on_login_accepted = [&](const std::string& sid, uint64_t seq) {
        fh.session = sid;
        LOG_INFO(COMP) << "logged in: session='" << sid << "' next seq "
                       << seq;
    };
    session.on_login_rejected = [&](char code) {
        LOG_ERROR(COMP) << "login rejected with code '" << code
                        << "' — terminating (no retry)";
        fh.exit_code = 5;
        connector.stop();
        reactor.stop();
    };
    session.on_end_of_session = [&]() {
        LOG_INFO(COMP) << "end of session (Z): published=" << fh.published
                       << " last_seq=" << fh.last_exch_seq
                       << " pub_seq=" << fh.pub_seq;
        session.logout(jnx::mono_ns());
        connector.flush();
        connector.stop();
        reactor.stop();
    };
    session.on_peer_silent = [&]() {
        LOG_WARN(COMP) << "peer silent for 15 s; reconnecting";
        connector.reconnect();
    };
    session.on_message = [&](uint64_t seq, const unsigned char* payload,
                             size_t len) {
        jnx::ItchMsg msg;
        const char* err = NULL;
        if (!jnx::decode(payload, len, msg, &err)) {
            ++fh.decode_errors;
            LOG_WARN(COMP) << "itch decode error at seq " << seq << ": "
                           << (err ? err : "?");
            return;
        }
        jnx::ApplyResult res = fh.market.apply(msg);
        fh.last_exch_seq = seq;
        ++fh.msgs_since_stats;
        if (!res.applied || res.trigger == 'T') {
            return; // T updates the clock but publishes nothing (pinned)
        }
        uint64_t exch_ns =
            jnx::make_timestamp(fh.market.seconds, msg.type == 'T' ? 0 : msg.ns);
        if (res.trigger == 'S') {
            fh.ctx.note_event(res.group, msg.event);
        }
        fh.ctx.note(res, exch_ns);

        jnx::Envelope env;
        env.epoch = fh.epoch;
        env.pub_seq = ++fh.pub_seq;
        env.session = fh.session;
        env.exch_seq = seq;
        env.exch_ns = exch_ns;
        env.trigger = res.trigger;
        jnx::UpdateRecord rec = jnx::make_update(fh.market, fh.ctx, res, env);
        unsigned char buf[jnx::UPDATE_WIRE_SIZE];
        size_t n = jnx::encode_update(rec, buf);
        // DB write FIRST (authoritative), then multicast.
        if (fh.db_connected) {
            if (!fh.db.send(buf, n)) {
                fh.db_connected = false;
                ++fh.db_write_fails;
            }
        }
        fh.mcast.send(buf, n);
        ++fh.published;
    };

    // DB reconnect loop: a 1 s reactor timer, never a thread.
    std::function<void()> db_timer_fn;
    db_timer_fn = [&]() {
        if (!fh.db_connected) {
            if (fh.try_db_connect()) {
                LOG_INFO(COMP) << "db link restored";
            }
        }
        reactor.call_later(1000000000ULL, db_timer_fn);
    };
    reactor.call_later(1000000000ULL, db_timer_fn);

    // Signal watcher + clean shutdown.
    std::function<void()> sig_timer_fn;
    sig_timer_fn = [&]() {
        if (g_stop) {
            LOG_INFO(COMP) << "signal received; shutting down cleanly";
            session.logout(jnx::mono_ns());
            connector.flush();
            connector.stop();
            reactor.stop();
            return;
        }
        reactor.call_later(200000000ULL, sig_timer_fn);
    };
    reactor.call_later(200000000ULL, sig_timer_fn);

    // 5 s stats line.
    std::function<void()> stats_timer_fn;
    stats_timer_fn = [&]() {
        LOG_INFO(COMP) << "stats: msgs/s=" << fh.msgs_since_stats / 5
                       << " exch_seq=" << fh.last_exch_seq
                       << " pub_seq=" << fh.pub_seq
                       << " books=" << fh.market.books.books().size()
                       << " orders=" << fh.market.books.orders().size()
                       << " db_connected=" << (fh.db_connected ? 1 : 0)
                       << " mcast_errors=" << fh.mcast.send_errors();
        fh.msgs_since_stats = 0;
        reactor.call_later(5000000000ULL, stats_timer_fn);
    };
    reactor.call_later(5000000000ULL, stats_timer_fn);

    LOG_INFO(COMP) << "starting live loop: itch " << itch_host << ":"
                   << itch_port << ", db " << fh.db_sock << " (connected="
                   << (fh.db_connected ? 1 : 0) << "), epoch=" << fh.epoch;
    connector.start();
    reactor.run();

    LOG_INFO(COMP) << "exit: published=" << fh.published
                   << " pub_seq=" << fh.pub_seq << " last_exch_seq="
                   << fh.last_exch_seq << " decode_errors="
                   << fh.decode_errors << " db_write_fails="
                   << fh.db_write_fails;
    return fh.exit_code;
}

// test_soupclient.cpp — sans-I/O SoupClientSession state machine against
// scripted byte sequences (no sockets).
#include "fh/soupclient.h"

#include <cstring>
#include <string>
#include <vector>

#include "common/minitest.h"
#include "soup/soup.h"

namespace {

const uint64_t SEC = 1000000000ULL;

std::vector<unsigned char> login_accepted(const char* session,
                                          uint64_t seq) {
    jnx::SoupLoginAccepted la;
    std::snprintf(la.session, sizeof(la.session), "%s", session);
    la.sequence = seq;
    unsigned char buf[jnx::SOUP_LOGIN_ACCEPTED_WIRE];
    size_t n = jnx::soup_build_login_accepted(la, buf);
    return std::vector<unsigned char>(buf, buf + n);
}

std::vector<unsigned char> sequenced(const std::string& payload) {
    unsigned char buf[128];
    size_t n = jnx::soup_build_packet(
        'S', reinterpret_cast<const unsigned char*>(payload.data()),
        payload.size(), buf);
    return std::vector<unsigned char>(buf, buf + n);
}

std::vector<unsigned char> bare(char type) {
    unsigned char buf[jnx::SOUP_BARE_WIRE];
    size_t n = jnx::soup_build_packet(type, NULL, 0, buf);
    return std::vector<unsigned char>(buf, buf + n);
}

// Count Soup packets of a given type in a raw byte stream.
int count_packets(const std::vector<unsigned char>& bytes, char type) {
    jnx::SoupFramer framer;
    if (!bytes.empty()) {
        framer.feed(&bytes[0], bytes.size());
    }
    jnx::SoupPacket pkt;
    int n = 0;
    while (framer.next(pkt)) {
        if (pkt.type == type) ++n;
    }
    return n;
}

} // namespace

TEST(soupclient_login_flow_and_self_counted_seq) {
    jnx::SoupClientSession s("USER", "PASS", "", 1);
    std::string got_session;
    uint64_t got_seq = 0;
    std::vector<std::pair<uint64_t, std::string> > msgs;
    s.on_login_accepted = [&](const std::string& sid, uint64_t seq) {
        got_session = sid;
        got_seq = seq;
    };
    s.on_message = [&](uint64_t seq, const unsigned char* p, size_t n) {
        msgs.push_back(std::make_pair(
            seq, std::string(reinterpret_cast<const char*>(p), n)));
    };

    s.start(0);
    std::vector<unsigned char> out;
    CHECK(s.take_output(out));
    // Exactly one LoginRequest queued.
    CHECK_EQ(count_packets(out, 'L'), 1);
    CHECK_EQ(static_cast<int>(s.state()),
             static_cast<int>(jnx::SoupClientSession::ST_LOGIN_SENT));

    std::vector<unsigned char> la = login_accepted("SIM0000001", 12563);
    s.on_bytes(&la[0], la.size(), 1 * SEC);
    CHECK_EQ(static_cast<int>(s.state()),
             static_cast<int>(jnx::SoupClientSession::ST_LIVE));
    CHECK_EQ(got_session, std::string("SIM0000001"));
    CHECK_EQ(got_seq, static_cast<uint64_t>(12563));

    // Two sequenced messages: self-counted 12563, 12564.
    std::vector<unsigned char> d1 = sequenced("hello");
    std::vector<unsigned char> d2 = sequenced("world");
    s.on_bytes(&d1[0], d1.size(), 2 * SEC);
    s.on_bytes(&d2[0], d2.size(), 2 * SEC);
    CHECK_EQ(msgs.size(), static_cast<size_t>(2));
    CHECK_EQ(msgs[0].first, static_cast<uint64_t>(12563));
    CHECK_EQ(msgs[0].second, std::string("hello"));
    CHECK_EQ(msgs[1].first, static_cast<uint64_t>(12564));
    CHECK_EQ(s.next_seq(), static_cast<uint64_t>(12565));
}

TEST(soupclient_login_rejected_terminal) {
    jnx::SoupClientSession s("USER", "PASS", "", 1);
    char code = '\0';
    s.on_login_rejected = [&](char c) { code = c; };
    s.start(0);
    std::vector<unsigned char> out;
    s.take_output(out);

    jnx::SoupLoginRejected rj;
    rj.reject_code = 'A';
    unsigned char buf[jnx::SOUP_LOGIN_REJECTED_WIRE];
    size_t n = jnx::soup_build_login_rejected(rj, buf);
    s.on_bytes(buf, n, 1 * SEC);
    CHECK_EQ(static_cast<int>(s.state()),
             static_cast<int>(jnx::SoupClientSession::ST_FAILED));
    CHECK_EQ(std::string(1, code), std::string("A"));
    CHECK_EQ(std::string(1, s.reject_code()), std::string("A"));
}

TEST(soupclient_heartbeat_after_1s_idle) {
    jnx::SoupClientSession s("USER", "PASS", "", 1);
    s.start(10 * SEC);
    std::vector<unsigned char> out;
    s.take_output(out); // drain the login request
    out.clear();

    // Under 1 s outbound idle: no heartbeat.
    s.on_tick(10 * SEC + SEC / 2);
    CHECK(!s.has_output());
    // Over 1 s: exactly one client heartbeat 'R'.
    s.on_tick(11 * SEC + 1);
    CHECK(s.take_output(out));
    CHECK_EQ(count_packets(out, 'R'), 1);
    // Timer was refreshed by the heartbeat itself.
    out.clear();
    s.on_tick(11 * SEC + SEC / 2);
    CHECK(!s.has_output());
}

TEST(soupclient_peer_silent_after_15s) {
    jnx::SoupClientSession s("USER", "PASS", "", 1);
    int silent = 0;
    s.on_peer_silent = [&]() { ++silent; };
    s.start(0);
    std::vector<unsigned char> out;
    s.take_output(out);

    std::vector<unsigned char> la = login_accepted("X", 1);
    s.on_bytes(&la[0], la.size(), 1 * SEC);

    s.on_tick(15 * SEC); // 14 s inbound silence: fine
    CHECK_EQ(silent, 0);
    s.on_tick(16 * SEC + 1); // >15 s: report
    CHECK_EQ(silent, 1);

    // Any inbound byte (e.g. a server heartbeat) resets the clock.
    std::vector<unsigned char> hb = bare('H');
    s.on_bytes(&hb[0], hb.size(), 17 * SEC);
    s.on_tick(18 * SEC);
    CHECK_EQ(silent, 1);
}

TEST(soupclient_end_of_session) {
    jnx::SoupClientSession s("USER", "PASS", "", 1);
    int ended = 0;
    s.on_end_of_session = [&]() { ++ended; };
    s.start(0);
    std::vector<unsigned char> out;
    s.take_output(out);
    std::vector<unsigned char> la = login_accepted("X", 5);
    s.on_bytes(&la[0], la.size(), 1 * SEC);
    std::vector<unsigned char> z = bare('Z');
    s.on_bytes(&z[0], z.size(), 2 * SEC);
    CHECK_EQ(ended, 1);
    CHECK_EQ(static_cast<int>(s.state()),
             static_cast<int>(jnx::SoupClientSession::ST_ENDED));
}

TEST(soupclient_reset_keeps_resume_point) {
    jnx::SoupClientSession s("USER", "PASS", "", 1);
    s.start(0);
    std::vector<unsigned char> out;
    s.take_output(out);
    std::vector<unsigned char> la = login_accepted("SESSA", 100);
    s.on_bytes(&la[0], la.size(), 1 * SEC);
    std::vector<unsigned char> d = sequenced("x");
    s.on_bytes(&d[0], d.size(), 2 * SEC); // consumed seq 100 -> next 101

    // Simulated TCP drop: reset, re-login must request SESSA @ 101.
    s.reset();
    CHECK_EQ(static_cast<int>(s.state()),
             static_cast<int>(jnx::SoupClientSession::ST_CONNECTED));
    s.start(3 * SEC);
    out.clear();
    CHECK(s.take_output(out));
    jnx::SoupFramer framer;
    framer.feed(&out[0], out.size());
    jnx::SoupPacket pkt;
    CHECK(framer.next(pkt));
    CHECK_EQ(std::string(1, pkt.type), std::string("L"));
    jnx::SoupLoginRequest req;
    const char* err = NULL;
    CHECK(jnx::soup_parse_login_request(&pkt.payload[0], pkt.payload.size(),
                                        req, &err));
    CHECK_EQ(std::string(req.requested_session), std::string("SESSA"));
    CHECK_EQ(req.requested_sequence, static_cast<uint64_t>(101));
}
